    const state = get();
    // BUG FIX: Prevent repeated calls if already dead or invalid state
    if (state.status !== GameStatus.PLAYING || state.isInvincible || state.health <= 0) return;

    // Dodge
    if (state.stats.dodge > 0 && Math.random() < state.stats.dodge) {
        return; 
    }

    if (state.skillLevels.barrier > 0 && state.barrierCooldown <= 0) {
         const barrierLevel = state.skillLevels.barrier;
         const duration = 1.0 + (barrierLevel * 0.2); 
         const cooldown = Math.max(5, 12 - barrierLevel); 
         get().triggerInvincibility(duration);
         const knockbackRadius = 10 + (barrierLevel * 2);
         const knockbackForce = 5 + (barrierLevel);
         window.dispatchEvent(new CustomEvent('barrier-trigger', {
             detail: { position: state.playerPosition, radius: knockbackRadius, force: knockbackForce }
         }));
         set({ barrierCooldown: cooldown });
         return; 
    }

    const reductionMultiplier = 100 / (100 + state.stats.defense);
    const actualDamage = Math.max(1, amount * reductionMultiplier);
    const newHealth = Math.max(0, state.health - actualDamage);

    window.dispatchEvent(new CustomEvent('damage', { 
        detail: { position: state.playerPosition, damage: actualDamage, isCrit: false, isPlayer: true } 
    }));

    if (newHealth <= 0) {
      // 1. Check Pet Revive
      if (state.equipment.pet && state.equipment.pet.petSkill === 'REVIVE' && state.petReviveCooldown <= 0) {
          set({
              health: state.stats.maxHealth * 0.5,
              petReviveCooldown: state.equipment.pet.petCooldown || 300,
              reviveAnimTimer: 2.0 // Trigger visual
          });
          get().triggerInvincibility(5.0); // 5s Invincibility
          get().addNotification("PHOENIX REVIVE!", COLORS.rarityLegendary, 'SYSTEM');
          return;
      }

      // 2. Check Inventory Revive Item
      const reviveIndex = state.inventory.findIndex(i => i.type === 'REVIVE');
      if (reviveIndex !== -1) {
          const reviveItem = state.inventory[reviveIndex];
          const newInv = [...state.inventory];
          if ((reviveItem.quantity || 1) > 1) {
              newInv[reviveIndex].quantity = (reviveItem.quantity || 1) - 1;
          } else {
              newInv.splice(reviveIndex, 1);
          }
          set({
              health: state.stats.maxHealth * 0.5,
              inventory: newInv,
              reviveAnimTimer: 2.0 // Trigger visual
          });
          get().triggerInvincibility(5.0); // 5s Invincibility
          get().addNotification("REVIVED BY GEM!", COLORS.rarityEpic, 'SYSTEM');
          return;
      }

      // UPDATE STATISTICS ON GAME OVER
      const newStats = { ...state.gameStats };
      newStats.totalRuns++;
      newStats.classRuns[state.hero]++;

      const currentTotalCP = calculateTotalCP(state.stats);
      if (currentTotalCP > newStats.highestCP) newStats.highestCP = currentTotalCP;

      if (state.wave > newStats.classHighestWave[state.hero]) {
          newStats.classHighestWave[state.hero] = state.wave;
      }

      if (state.wave > newStats.highestWave) {
          newStats.highestWave = state.wave;
          newStats.bestRunClass = state.hero;
      }

      set({ 
          health: 0, 
          status: GameStatus.GAME_OVER,
          recentRuns: [state.wave, ...state.recentRuns.slice(0, 4)],
          score: state.score + state.accumulatedWaveGold,
          gameStats: newStats
      });
    } else {
      set({ health: newHealth });
    }
  },

  // ... (rest of methods like breakCrate, damageCrate, useMana, heal, restoreMana, setPlayerPosition, setInvincible, triggerInvincibility, spawnDrop, handleInventoryFull, collectDrop, triggerSkillCooldown, activateRage, activateEarthwall, activateWarVitality, activateSprint, updatePassiveCooldowns, advanceWave, setBossData, tickCooldowns)

  breakCrate: (id) => {
    const { crates, spawnDrop } = get();
    const index = crates.findIndex(c => c.id === id);
    if (index === -1) return;
    const crate = crates[index];
    if (!crate.active) return;

    const newCrates = [...crates];
    newCrates[index] = { ...crate, active: false };
    set({ crates: newCrates });

    spawnDrop(crate.position, 'XP', 50);
    const r = Math.random();
    if (r > 0.85) {
        spawnDrop(crate.position.clone().add(new Vector3(1,0,0)), 'ITEM', 0);
    } else if (r > 0.5) {
        spawnDrop(crate.position.clone().add(new Vector3(0.5,0,0.5)), 'GOLD', 10);
    }
  },

  damageCrate: (id, amount) => {
      set((state) => {
          const crateIndex = state.crates.findIndex(c => c.id === id);
          if (crateIndex === -1) return { crates: state.crates };
          const newCrates = [...state.crates];
          const crate = { ...newCrates[crateIndex] };
          if (!crate.active) return { crates: state.crates };

          crate.hp -= amount;
          newCrates[crateIndex] = crate;
          return { crates: newCrates };
      });
      const state = get();
      const crate = state.crates.find(c => c.id === id);
      if (crate && crate.active && crate.hp <= 0) {
          get().breakCrate(id);
      }
  },

  useMana: (amount) => {
      const { mana, hero } = get();
      const actualCost = hero === 'WIZARD' ? Math.ceil(amount * 1.3) : amount;
      if (mana >= actualCost) {
          set({ mana: mana - actualCost });
          return true;
      }
      return false;
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  restoreMana: (amount) => set((state) => ({ 
    mana: Math.min(state.mana + amount, state.stats.maxMana) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),
  setInvincible: (invincible) => set({ isInvincible: invincible }),

  triggerInvincibility: (duration) => set((state) => ({ 
      invincibilityTimer: Math.max(state.invincibilityTimer, duration),
      isInvincible: true 
  })),

  spawnDrop: (position, type, value, rarityOverride) => set((state) => {
      if (state.drops.length > 99) return { drops: state.drops };

      // Clamp spawn position to arena size (with slight buffer)
      const maxDist = (ARENA_SIZE / 2) - 2;
      const dist = position.length();
      if (dist > maxDist) {
          position.normalize().multiplyScalar(maxDist);
          position.y = 0; // Ensure on ground
      }

      let item = null;
      if (type === 'ITEM') {
          let pool = ITEMS_POOL.filter(i => i.type !== 'PET');
          if (rarityOverride) {
              pool = pool.filter(i => i.rarity === rarityOverride && i.type !== 'POTION' && i.type !== 'CORE');
              if (pool.length === 0) pool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'PET');
          } else {
               const r = Math.random();
               if (r > 0.90) { pool = pool.filter(i => i.type === 'POTION'); } 
               else if (r > 0.60) { pool = pool.filter(i => i.type === 'CORE'); } 
               else { pool = pool.filter(i => (i.rarity === 'COMMON' || i.rarity === 'RARE') && i.type !== 'POTION' && i.type !== 'CORE'); }
          }

          if (pool.length > 0) {
              const hero = get().hero;
              const weightedPool: Item[] = [];
              pool.forEach(p => {
                  weightedPool.push(p); weightedPool.push(p); 
                  if (p.type === 'WEAPON' && p.classType === hero) { weightedPool.push(p); }
              });
              const template = weightedPool[Math.floor(Math.random() * weightedPool.length)];
              item = { ...template, id: Math.random().toString(), stats: { ...template.stats }, onHitEffect: template.onHitEffect }; 
              item.quantity = 1;
              if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
                   const plusChance = Math.random();
                   let plus = 0;
                   if (plusChance > 0.95) plus = 3; else if (plusChance > 0.85) plus = 2; else if (plusChance > 0.60) plus = 1;
                   if (plus > 0) {
                       item.level += plus;
                       Object.keys(item.stats).forEach((k) => {
                           const key = k as keyof PlayerStats;
                           const v = item.stats[key]!; // Base Stats (Level 1)
                           const newVal = v * item.level; // Linear Scaling: Base * New Level
                           item.stats[key] = parseFloat(newVal.toFixed(2));
                       });
                   }
              }
          }
      }
      return { drops: [...state.drops, { id: Math.random(), position: position.clone(), type, value, item, active: true, rotation: Math.random() * Math.PI }] };
  }),

  handleInventoryFull: () => {
      const now = Date.now();
      const last = get().lastInventoryFullNotification;
      if (now - last > 10000) { 
          get().addNotification("INVENTORY FULL", "red", "SYSTEM");
          set({ lastInventoryFullNotification: now });
      }
  },

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);
      const { addExperience, addScore, addGems, addNotification, equipment, level, equipItem } = get();

      if (drop.type === 'ITEM' && drop.item) {
          const item = drop.item;
          const isStackable = item.type === 'POTION' || item.type === 'CORE' || item.type === 'REVIVE';

          if (isStackable) {
              // Find existing stack with space
              const existingStack = state.inventory.find(i => i.name === item.name && (i.quantity || 1) < POTION_STACK_LIMIT);
              if (existingStack) {
                  existingStack.quantity = (existingStack.quantity || 1) + 1;
                  addNotification(`Looted ${item.name} (x1)`, COLORS.rarityCommon, 'ITEM');
                  return { drops: newDrops, inventory: [...state.inventory] };
              }
          }

          // Check inventory limit before adding new item/stack
          if (state.inventory.length >= state.maxInventorySlots) {
              get().handleInventoryFull();
              return { drops: state.drops };
          }

          const rarityColors: Record<string, string> = { 'COMMON': COLORS.rarityCommon, 'RARE': COLORS.rarityRare, 'EPIC': COLORS.rarityEpic, 'LEGENDARY': COLORS.rarityLegendary, 'MYTHIC': COLORS.rarityMythic };
          let action = undefined;
          if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
              const slot = item.type.toLowerCase() as keyof typeof equipment;
              const currentEquip = equipment[slot];
              const newCP = calculateItemCP(item);
              const oldCP = currentEquip ? calculateItemCP(currentEquip) : 0;
              let reqLevel = 1;
              if (item.rarity === 'RARE') reqLevel = 5; if (item.rarity === 'EPIC') reqLevel = 10; if (item.rarity === 'LEGENDARY') reqLevel = 15; if (item.rarity === 'MYTHIC') reqLevel = 20;
              const classMatch = !item.classType || item.classType === state.hero;
              if (newCP > oldCP && level >= reqLevel && classMatch) { action = { label: 'EQUIP', onClick: () => get().equipItem(item) }; }
          }

          addNotification(`Looted ${item.name} ${item.level > 1 ? `+${item.level-1}` : ''}`, rarityColors[item.rarity], 'ITEM', action);
          return { drops: newDrops, inventory: [...state.inventory, { ...item, quantity: 1 }] };
      }

      if (drop.type === 'XP') { addExperience(drop.value); } 
      else if (drop.type === 'GOLD') { addScore(drop.value); } 
      else if (drop.type === 'GEM') { addGems(drop.value); } 

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => {
      const cooldown = state.skillMaxCooldowns[skill] * (1 - state.stats.cooldownReduction);
      return { skills: { ...state.skills, [skill]: cooldown } };
  }),

  activateRage: () => set((state) => {
      const newStats = calculateStats(state.baseStats, state.equipment, true, state.sprintTimer > 0);
      return { rageMode: true, rageTimer: 4.0, stats: newStats };
  }),

  activateEarthwall: (pos) => set((state) => ({ 
      earthwall: { active: true, position: pos, timer: 4.0, radius: 12.0 } // Increased radius to 12
  })),

  activateWarVitality: () => set((state) => ({ warVitalityTimer: 6.0 })),

  activateSprint: () => {
      const state = get();
      const newStats = calculateStats(state.baseStats, state.equipment, state.rageMode, true);
      set({ sprintTimer: 4.0, stats: newStats, invincibilityTimer: Math.max(state.invincibilityTimer, 4.0), isInvincible: true });
  },

  updatePassiveCooldowns: (partial) => set((state) => ({ passiveSkillState: { ...state.passiveSkillState, ...partial } })),

  advanceWave: () => {
      const upgrades = generateUpgradeOptions(get().hero);
      set((state) => ({ 
          wave: state.wave + 1, 
          waveTimer: 0,
          accumulatedWaveGold: state.accumulatedWaveGold + 100,
          status: GameStatus.LEVEL_UP,
          upgradeOptions: upgrades
      }));
  },

  setBossData: (data) => set(state => ({ bossData: { ...state.bossData, ...data } })),

  tickCooldowns: (delta) => {
      const state = get();
      const newSkills = {
          dash: Math.max(0, state.skills.dash - delta),
          q: Math.max(0, state.skills.q - delta),
          r: Math.max(0, state.skills.r - delta),
          e: Math.max(0, state.skills.e - delta),
      };

      let rageTimer = state.rageTimer;
      let rageMode = state.rageMode;
      let sprintTimer = state.sprintTimer;
      let stats = state.stats;

      // Update E Skill Buffs
      let earthwall = { ...state.earthwall };
      if (earthwall.active) {
          earthwall.timer -= delta;
          if (earthwall.timer <= 0) earthwall.active = false;
      }

      let warVitalityTimer = state.warVitalityTimer;
      if (warVitalityTimer > 0) {
          warVitalityTimer -= delta;
          // War Vitality: Regen 10 HP/sec
          const healAmt = 10 * delta;
          if (state.health < state.stats.maxHealth) {
              get().heal(healAmt);
          }
      }

      if (sprintTimer > 0) {
          sprintTimer -= delta;
          if (sprintTimer <= 0) {
              // Stats reset handled below
          }
      }

      // Check Stats Re-calc
      let recalc = false;
      if (rageMode) {
          rageTimer -= delta;
          if (rageTimer <= 0) {
              rageMode = false;
              rageTimer = 0;
              recalc = true;
          }
      }
      if (state.sprintTimer > 0 && sprintTimer <= 0) recalc = true;

      if (recalc) {
          stats = calculateStats(state.baseStats, state.equipment, rageMode, sprintTimer > 0);
      }

      const newBarrierCooldown = Math.max(0, state.barrierCooldown - delta);
      const newLevelUpTimer = Math.max(0, state.levelUpVisualTimer - delta);
      const newReviveAnimTimer = Math.max(0, state.reviveAnimTimer - delta); // Update revive anim
      const newPetReviveCooldown = Math.max(0, state.petReviveCooldown - delta);

      let newInvincibilityTimer = state.invincibilityTimer;
      let newIsInvincible = state.isInvincible;
      if (state.invincibilityTimer > 0) {
          newInvincibilityTimer -= delta;
          if (newInvincibilityTimer <= 0) {
              newInvincibilityTimer = 0;
              newIsInvincible = false;
          } else {
              newIsInvincible = true;
          }
      }

      const regenAmount = (state.stats.regen) * delta;
      const manaRegenAmount = state.stats.manaRegen * delta;
      const newHealth = Math.min(state.stats.maxHealth, state.health + regenAmount);
      const newMana = Math.min(state.stats.maxMana, state.mana + manaRegenAmount);

      let newPotionCD = Math.max(0, state.potionCooldown - delta);
      let newHealthAfterPot = newHealth;
      let newManaAfterPot = newMana;
      let inventory = state.inventory;

      if (newPotionCD <= 0) {
          // Updated Potion Logic using restoreAmount
          const hpThreshold = state.stats.maxHealth * 0.3;
          const manaThreshold = state.stats.maxMana * 0.3;
          let usedPotion = false;
          if (newHealth < hpThreshold) {
              const hpPotIndex = inventory.findIndex(i => i.type === 'POTION' && i.name === 'Health Potion');
              if (hpPotIndex !== -1) {
                  const pot = inventory[hpPotIndex];
                  newHealthAfterPot = Math.min(state.stats.maxHealth, newHealth + (pot.restoreAmount || 50));
                  usedPotion = true;
                  inventory = [...inventory];
                  if ((pot.quantity || 1) > 1) { inventory[hpPotIndex] = { ...pot, quantity: (pot.quantity || 1) - 1 }; } 
                  else { inventory.splice(hpPotIndex, 1); }
              }
          }
          if (!usedPotion && newMana < manaThreshold) {
               const manaPotIndex = inventory.findIndex(i => i.type === 'POTION' && i.name === 'Mana Potion');
               if (manaPotIndex !== -1) {
                  const pot = inventory[manaPotIndex];
                  newManaAfterPot = Math.min(state.stats.maxMana, newMana + (pot.restoreAmount || 50));
                  usedPotion = true;
                  inventory = [...inventory];
                  if ((pot.quantity || 1) > 1) { inventory[manaPotIndex] = { ...pot, quantity: (pot.quantity || 1) - 1 }; } 
                  else { inventory.splice(manaPotIndex, 1); }
               }
          }
          if (usedPotion) newPotionCD = 5; 
      }

      set({
          skills: newSkills,
          health: newHealthAfterPot,
          mana: newManaAfterPot,
          stats: stats,
          rageMode: rageMode,
          rageTimer: rageTimer,
          sprintTimer: Math.max(0, sprintTimer),
          earthwall: earthwall,
          warVitalityTimer: Math.max(0, warVitalityTimer),
          potionCooldown: newPotionCD,
          barrierCooldown: newBarrierCooldown,
          inventory: inventory,
          waveTimer: state.waveTimer + delta,
          invincibilityTimer: newInvincibilityTimer,
          isInvincible: newIsInvincible,
          levelUpVisualTimer: newLevelUpTimer,
          reviveAnimTimer: newReviveAnimTimer, // Set
          petReviveCooldown: newPetReviveCooldown,
      });
  },

  upgradeItem: (item) => {
      const state = get();
      if (item.level >= 10) {
          set({ actionResult: { type: 'UPGRADE', success: false, message: "Max Level Reached!" } });
          return { success: false, msg: "Max Level", newItem: item };
      }

      const core = state.inventory.find(i => i.type === 'CORE');
      const coreIndex = state.inventory.findIndex(i => i.type === 'CORE');
      const requiredCores = Math.ceil(item.level / 2);
      const goldCost = Math.floor(item.price * item.level * 0.5);

      if (state.score < goldCost) {
          set({ actionResult: { type: 'UPGRADE', success: false, message: "Not enough Gold!" } });
          return { success: false, msg: "Not enough Gold", newItem: item };
      }
      if (!core || (core.quantity || 1) < requiredCores) {
          set({ actionResult: { type: 'UPGRADE', success: false, message: `Need ${requiredCores} Cores` } });
          return { success: false, msg: `Need ${requiredCores} Cores`, newItem: item };
      }

      // Updated Success Rate Logic: 100% until +2, then -10% per level
      // Level 1 -> 2: (level is 1) 100%
      // Level 2 -> 3: (level is 2) 100%
      // Level 3 -> 4: (level is 3) 90%
      // Level 4 -> 5: (level is 4) 80%
      // Formula: if level < 3 return 100 else 100 - (level - 2) * 10
      let chance = 100;
      if (item.level >= 3) {
          chance = Math.max(10, 100 - ((item.level - 2) * 10));
      }

      const roll = Math.random() * 100;
      const success = roll < chance;

      const newInventory = [...state.inventory];
      const coreItem = newInventory[coreIndex];
      if ((coreItem.quantity || 1) > requiredCores) { coreItem.quantity = (coreItem.quantity || 1) - requiredCores; } else { newInventory.splice(coreIndex, 1); }
      set({ score: state.score - goldCost, inventory: newInventory });

      if (success) {
           let upgradedItem: Item = { ...item };
           const upgradeLogic = (i: Item) => {
              if (i === item) {
                  const updatedStats = { ...i.stats };
                  Object.keys(updatedStats).forEach(k => {
                      const key = k as keyof PlayerStats; 
                      const val = updatedStats[key]!;

                      // NEW LINEAR SCALING LOGIC: (Current / Level) * (Level + 1)
                      const lvl = Math.max(1, i.level);
                      const base = val / lvl;
                      const next = base * (lvl + 1);
                      updatedStats[key] = parseFloat(next.toFixed(2));
                  });
                  upgradedItem = { ...i, level: i.level + 1, stats: updatedStats };
                  return upgradedItem;
              }
              return i;
          };
          const updatedInventory = get().inventory.map(upgradeLogic);
          const updatedEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
              pet: state.equipment.pet ? upgradeLogic(state.equipment.pet) : null,
          };
          const newStats = calculateStats(state.baseStats, updatedEquipment, state.rageMode, state.sprintTimer > 0);
          set({ inventory: updatedInventory, equipment: updatedEquipment, stats: newStats, actionResult: { type: 'UPGRADE', success: true, message: "Upgrade Successful!", item: upgradedItem } });
          return { success: true, msg: "Upgrade Successful!", newItem: upgradedItem };
      } else { 
          set({ actionResult: { type: 'UPGRADE', success: false, message: "Upgrade Failed..." } });
          return { success: false, msg: "Upgrade Failed...", newItem: item }; 
      }
  },

  resetGame: () => set({ status: GameStatus.MENU }),
  addNotification: (message, color = 'white', type = 'ITEM', action) => set(state => ({ notifications: [...state.notifications, { id: Math.random().toString(), message, color, type, action }] })),
  removeNotification: (id) => set(state => ({ notifications: state.notifications.filter(n => n.id !== id) })),

  updateMinimapEnemies: (enemies) => set({ minimapEnemies: enemies }), // Update action

  // ... (equipItem, unequipItem, autoEquip, buyItem, sellItem, etc. unchanged)
  equipItem: (item) => set((state) => {
      const req = RARITY_LEVEL_REQ[item.rarity] || 1;
      if (state.level < req) {
          get().addNotification(`Requires Level ${req}`, 'red', 'SYSTEM');
          return {};
      }

      let newInventory = state.inventory.filter(i => i.id !== item.id);
      let slot: 'weapon' | 'armor' | 'accessory' | 'pet' | null = null;
      if (item.type === 'WEAPON') slot = 'weapon';
      if (item.type === 'ARMOR') slot = 'armor';
      if (item.type === 'ACCESSORY') slot = 'accessory';
      if (item.type === 'PET') slot = 'pet';

      if (!slot) return {};

      let oldItem = state.equipment[slot];
      if (oldItem) {
          newInventory.push(oldItem);
      }

      const newEquipment = { ...state.equipment, [slot]: item };

      return {
          inventory: newInventory,
          equipment: newEquipment,
          stats: calculateStats(state.baseStats, newEquipment, state.rageMode, state.sprintTimer > 0)
      };
  }),

  unequipItem: (slot) => set((state) => {
      const item = state.equipment[slot];
      if (!item) return {};
      if (state.inventory.length >= state.maxInventorySlots) {
          get().handleInventoryFull();
          return {};
      }

      const newEquipment = { ...state.equipment, [slot]: null };
      return {
          equipment: newEquipment,
          inventory: [...state.inventory, item],
          stats: calculateStats(state.baseStats, newEquipment, state.rageMode, state.sprintTimer > 0)
      };
  }),

  autoEquip: () => {
      const state = get();
      const slots = ['weapon', 'armor', 'accessory', 'pet'] as const;
      let newEquipment = { ...state.equipment };
      let newInventory = [...state.inventory];
      let changed = false;

      slots.forEach(slot => {
          let type: ItemType = 'WEAPON';
          if (slot === 'armor') type = 'ARMOR';
          if (slot === 'accessory') type = 'ACCESSORY';
          if (slot === 'pet') type = 'PET';

          const candidates = newInventory.filter(i => {
              // Level req check
              const req = RARITY_LEVEL_REQ[i.rarity] || 1;
              if (state.level < req) return false;
              return i.type === type && (!i.classType || i.classType === state.hero);
          });
          if (candidates.length === 0) return;

          // Find candidate with highest CP
          const bestCandidate = candidates.reduce((prev, current) => {
              return calculateItemCP(current) > calculateItemCP(prev) ? current : prev;
          });

          const currentItem = newEquipment[slot];
          const currentCP = currentItem ? calculateItemCP(currentItem) : -1;

          if (calculateItemCP(bestCandidate) > currentCP) {
              changed = true;
              // Swap
              if (currentItem) {
                  newInventory.push(currentItem);
              }
              newEquipment[slot] = bestCandidate;
              // Remove best candidate from inventory
              newInventory = newInventory.filter(i => i.id !== bestCandidate.id);
          }
      });

      if (changed) {
          set({
              equipment: newEquipment,
              inventory: newInventory,
              stats: calculateStats(state.baseStats, newEquipment, state.rageMode, state.sprintTimer > 0)
          });
          get().addNotification("Auto Equipped Best Gear", COLORS.uiAccent, 'SYSTEM');
      } else {
          get().addNotification("Best gear already equipped", COLORS.uiPrimary, 'SYSTEM');
      }
  },

  buyItem: (item, quantity = 1) => {
      const state = get();
      if (state.score >= item.price * quantity) {
          if (state.inventory.length + quantity > state.maxInventorySlots && item.type !== 'POTION' && item.type !== 'CORE') {
              get().handleInventoryFull();
              return false;
          }

          let newInv = [...state.inventory];
          for(let i=0; i<quantity; i++) {
              const isStackable = item.type === 'POTION' || item.type === 'CORE';
              const existingStack = newInv.find(x => x.name === item.name && isStackable && (x.quantity || 1) < POTION_STACK_LIMIT);

              if (existingStack) {
                  existingStack.quantity = (existingStack.quantity || 1) + 1;
              } else {
                  newInv.push({ ...item, id: Math.random().toString(), quantity: 1 });
              }
          }

          set({ score: state.score - (item.price * quantity), inventory: newInv });
          get().addNotification(`Bought ${quantity}x ${item.name}`, 'yellow', 'SYSTEM');
          return true;
      }
      return false;
  },

  sellItem: (item) => set((state) => {
      const sellPrice = Math.floor(item.price * 0.3);
      const newInv = state.inventory.filter(i => i.id !== item.id);
      return { score: state.score + sellPrice, inventory: newInv };
  }),

  sellItems: (items) => set((state) => {
      let total = 0;
      const ids = new Set(items.map(i => i.id));
      const newInv = state.inventory.filter(i => {
          if (ids.has(i.id)) {
              total += Math.floor(i.price * 0.3);
              return false;
          }
          return true;
      });
      return { score: state.score + total, inventory: newInv };
  }),

  massSell: (rarity) => set((state) => {
      let total = 0;
      let count = 0;
      const newInv = state.inventory.filter(i => {
          if (i.rarity === rarity && i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE') {
              total += Math.floor(i.price * 0.3);
              count++;
              return false;
          }
          return true;
      });
      get().addNotification(`Sold ${count} ${rarity} items for ${total} G`, 'yellow', 'SYSTEM');
      return { score: state.score + total, inventory: newInv };
  }),

  recycleItem: (item) => set((state) => {
      const newInv = state.inventory.filter(i => i.id !== item.id);
      const mat = item.rarity;
      return { 
          inventory: newInv, 
          materials: { ...state.materials, [mat]: state.materials[mat] + 1 } 
      };
  }),

  massRecycle: (rarity) => set((state) => {
      let count = 0;
      const newInv = state.inventory.filter(i => {
          if (i.rarity === rarity && i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE') {
              count++;
              return false;
          }
          return true;
      });
      return {
          inventory: newInv,
          materials: { ...state.materials, [rarity]: state.materials[rarity] + count }
      };
  }),

  combineMaterials: (rarity) => set((state) => {
      const have = state.materials[rarity];
      if (have < 10) return {};

      let nextRarity: Rarity | null = null;
      if (rarity === 'COMMON') nextRarity = 'RARE';
      if (rarity === 'RARE') nextRarity = 'EPIC';
      if (rarity === 'EPIC') nextRarity = 'LEGENDARY';
      if (rarity === 'LEGENDARY') nextRarity = 'MYTHIC';

      if (!nextRarity) return {};

      return {
          materials: {
              ...state.materials,
              [rarity]: have - 10,
              [nextRarity]: state.materials[nextRarity] + 1
          }
      };
  }),

  craftItem: (rarity) => {
      const state = get();
      if (state.materials[rarity] < 3) {
          set({ actionResult: { type: 'CRAFT', success: false, message: `Need 3 ${rarity} Materials` } });
          return false;
      }

      let pool = ITEMS_POOL.filter(i => i.rarity === rarity && i.type !== 'POTION' && i.type !== 'CORE');
      if (pool.length === 0) return false;

      const hero = state.hero;
      const weightedPool: Item[] = [];
      pool.forEach(p => {
          weightedPool.push(p);
          if (p.type === 'WEAPON' && p.classType === hero) weightedPool.push(p); 
      });

      const template = weightedPool[Math.floor(Math.random() * weightedPool.length)];
      const item = { ...template, id: Math.random().toString(), quantity: 1 };

      set({ 
          materials: { ...state.materials, [rarity]: state.materials[rarity] - 3 },
          inventory: [...state.inventory, item],
          actionResult: { type: 'CRAFT', success: true, message: `Crafted ${item.name}!`, item }
      });
      get().addNotification(`Crafted ${item.name}!`, COLORS.uiAccent, 'ITEM');
      return true;
  },

  buyInventorySlots: () => {
      const state = get();
      const cost = 1000 * (Math.floor((state.maxInventorySlots - INVENTORY_LIMIT) / 5) + 1);
      if (state.score >= cost) {
          set({ score: state.score - cost, maxInventorySlots: state.maxInventorySlots + 5 });
          return true;
      }
      return false;
  },

  performSummon: (amount) => {
      const state = get();
      if (state.inventory.length + amount > state.maxInventorySlots) {
          set({ actionResult: { type: 'CRAFT', success: false, message: "Inventory Full!" } });
          get().addNotification("Inventory Full!", "red", "SYSTEM");
          return false;
      }

      const cost = amount === 1 ? 100 : 900;
      if (state.gems < cost) return false;

      const results: Item[] = [];
      for(let i=0; i<amount; i++) {
          const r = Math.random();
          let rarity: Rarity = 'COMMON';

          // Updated Summon Probability (50% rarer high tier)
          // Old: M 1%, L 4%, E 15%, R 30%
          // New: M 0.5%, L 2%, E 7.5%, R 20%
          if (r > 0.995) rarity = 'MYTHIC';
          else if (r > 0.975) rarity = 'LEGENDARY';
          else if (r > 0.90) rarity = 'EPIC';
          else if (r > 0.70) rarity = 'RARE';

          let pool = [...ITEMS_POOL, ...PETS_POOL].filter(it => it.rarity === rarity);
          if (pool.length === 0) pool = ITEMS_POOL;

          const template = pool[Math.floor(Math.random() * pool.length)];
          results.push({ ...template, id: Math.random().toString(), quantity: 1 });
      }

      set({ 
          gems: state.gems - cost,
          gachaResults: results,
          status: GameStatus.GACHA_REVEAL,
          inventory: [...state.inventory, ...results]
      });
      return true;
  },

  clearGachaResults: () => set({ status: GameStatus.PLAYING, gachaResults: [] }),

  upgradeSkill: (skill) => set((state) => {
      const currentLevel = state.skillLevels[skill];
      const cost = skill === 'special' ? 5 : (currentLevel === 0 ? 3 : currentLevel + 1);

      if (state.skillPoints >= cost) {
          const newLevels = { ...state.skillLevels, [skill]: currentLevel + 1 };

          let newActiveQ = state.activeAbilityQ;
          if (skill === 'piercing') newActiveQ = 'PIERCING_SHOT';
          if (skill === 'gravity') newActiveQ = 'GRAVITY_SPELL';
          if (skill === 'rage') newActiveQ = 'RAGE';

          return {
              skillPoints: state.skillPoints - cost,
              skillLevels: newLevels,
              activeAbilityQ: newActiveQ
          };
      }
      return {};
  }),

  applyUpgrade: (upgrade: Upgrade) => set((state) => {
      const newBase = { ...state.baseStats };
      let newSkillLevels = { ...state.skillLevels };
      const newPassiveState = { ...state.passiveSkillState };

      if (upgrade.type === 'HEALTH') newBase.maxHealth += upgrade.value;
      if (upgrade.type === 'MAX_MANA') newBase.maxMana += upgrade.value;
      if (upgrade.type === 'DEFENSE') newBase.defense += upgrade.value;
      if (upgrade.type === 'SPEED') newBase.moveSpeed += upgrade.value; 
      if (upgrade.type === 'DAMAGE') newBase.damage = Math.ceil(newBase.damage * (1 + upgrade.value)); 
      if (upgrade.type === 'FIRE_RATE') newBase.fireRate += upgrade.value;
      if (upgrade.type === 'MULTISHOT') newBase.multishot += upgrade.value;
      if (upgrade.type === 'CRIT_RATE') newBase.critRate += upgrade.value;
      if (upgrade.type === 'CRIT_DAMAGE') newBase.critDamage += upgrade.value;
      if (upgrade.type === 'DASH_COOLDOWN') newBase.dashCooldown -= 0.5;

      if (upgrade.type.startsWith('SKILL_')) {
          let key: keyof SkillLevels | null = null;
          if (upgrade.type === 'SKILL_ORBITAL') key = 'orbital';
          if (upgrade.type === 'SKILL_THUNDER') key = 'thunder';
          if (upgrade.type === 'SKILL_REGEN') key = 'regen';
          if (upgrade.type === 'SKILL_MAGNET') key = 'magnet';
          if (upgrade.type === 'SKILL_DASH') key = 'dash';
          if (upgrade.type === 'SKILL_WEAPON') key = 'weapon';
          if (upgrade.type === 'SKILL_BARRIER') key = 'barrier';
          if (upgrade.type === 'SKILL_STORM') key = 'storm';

          if (upgrade.type === 'SKILL_PIERCING') key = 'piercing';
          if (upgrade.type === 'SKILL_BURNING') key = 'burning';
          if (upgrade.type === 'SKILL_FREEZING') key = 'freezing';

          if (upgrade.type === 'SKILL_GRAVITY') key = 'gravity';
          if (upgrade.type === 'SKILL_FREEZE_SPELL') key = 'freezeSpell';

          if (upgrade.type === 'SKILL_RAGE') key = 'rage';
          if (upgrade.type === 'SKILL_STAMP') key = 'stamp';

          if (key) {
              newSkillLevels[key]++;
          }
      }

      let newActiveQ = state.activeAbilityQ;
      if (upgrade.type === 'SKILL_PIERCING' && !newActiveQ) newActiveQ = 'PIERCING_SHOT';
      if (upgrade.type === 'SKILL_GRAVITY' && !newActiveQ) newActiveQ = 'GRAVITY_SPELL';
      if (upgrade.type === 'SKILL_RAGE' && !newActiveQ) newActiveQ = 'RAGE';

      return {
          baseStats: newBase,
          stats: calculateStats(newBase, state.equipment, state.rageMode, state.sprintTimer > 0),
          skillLevels: newSkillLevels,
          passiveSkillState: newPassiveState,
          activeAbilityQ: newActiveQ
      };
  }),

  selectUpgrade: (upgrade: Upgrade) => {
      get().applyUpgrade(upgrade);
      set({ status: GameStatus.PLAYING });
  }

}));

import React, { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();
const pushDir = new Vector3();

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid: React.MutableRefObject<SpatialHashGrid>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef, enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const stunIconsRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, takeDamage, status, level, stats, spawnDrop, wave, waveTimer, advanceWave, addNotification, setBossData, earthwall, updateMinimapEnemies, obstacles } = useGameStore();

  // Use the lifted Ref
  const enemies = enemiesDataRef;

  const spawnTimer = useRef(0);
  const dotTicker = useRef(0);
  const waveState = useRef({ wave: 1, bossSpawned: false, eliteSpawned: false });
  const minimapThrottle = useRef(0); 

  // Handle Barrier Knockback Event
  useEffect(() => {
    const handleBarrier = (e: CustomEvent) => {
        const { position, radius, force } = e.detail;

        enemies.current.forEach(enemy => {
            if (enemy.active) {
                const dist = enemy.position.distanceTo(position);
                if (dist < radius) {
                    const dir = new Vector3().subVectors(enemy.position, position).normalize();
                    enemy.position.add(dir.multiplyScalar(force));
                    // Stun briefly
                    enemy.freezeTimer = 0.5;
                }
            }
        });
    };

    window.addEventListener('barrier-trigger', handleBarrier as EventListener);
    return () => window.removeEventListener('barrier-trigger', handleBarrier as EventListener);
  }, []);

  // --- RESET ENEMIES ON NEW RUN ---
  useEffect(() => {
      if (status === GameStatus.PLAYING && wave === 1 && waveTimer < 0.2) {
          // Hard Reset of Enemy Refs
          enemies.current.forEach(e => {
              e.active = false;
              e.health = 0;
              e.position.set(0, -100, 0); // Move away
          });
          if (meshRef.current) {
              // Force update visual to hide immediately
              for (let i = 0; i < MAX_ENEMIES; i++) {
                  dummy.position.set(0, -100, 0);
                  dummy.updateMatrix();
                  meshRef.current.setMatrixAt(i, dummy.matrix);
              }
              meshRef.current.instanceMatrix.needsUpdate = true;
          }
      }
  }, [status, wave, waveTimer]);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    // 0. Spatial Grid Reset
    spatialGrid.current.clear();

    const activeBullets = bulletsDataRef.current;

    // Reset pull counts for Blackhole bullets each frame
    activeBullets.forEach(b => { 
        if(b.active && b.type === 'BLACKHOLE') {
            b.currentPullCount = 0; 
        }
    });

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current; // Attach for legacy raycasting if needed, but we try to avoid it
    }

    // Wave Progression Logic
    if (waveTimer > 30) {
        advanceWave();
    }

    // Wave State Update
    if (wave !== waveState.current.wave) {
        waveState.current.wave = wave;
        waveState.current.bossSpawned = false;
        waveState.current.eliteSpawned = false;
    }

    // 1. Spawning Logic
    spawnTimer.current += delta;
    // 50% less spawning: doubled interval
    const spawnRate = Math.max(0.1, (0.8 - (level * 0.02) - (wave * 0.05)) * 2.0);

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            enemy.burnTimer = 0;
            enemy.poisonTimer = 0;
            enemy.freezeTimer = 0;
            enemy.slowTimer = 0;
            enemy.slowFactor = 0;

            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const hpMult = 1 + (wave * 0.5) + (level * 0.1);
            const speedMult = 1 + (wave * 0.05);
            const globalHpReduction = 0.4;
            const r = Math.random();

            let isBoss = false;
            let isElite = false;

            if (wave % 10 === 0 && !waveState.current.bossSpawned) {
                isBoss = true;
                waveState.current.bossSpawned = true;
                const bossName = wave % 20 === 0 ? "VOID REAPER" : "ABYSS LORD";
                addNotification(`⚠️ ${bossName} APPEARED ⚠️`, COLORS.enemyBoss, 'BOSS');
                setBossData({ active: true, name: bossName, hp: 1, maxHp: 1 }); 
            } else if (wave % 5 === 0 && wave % 10 !== 0 && !waveState.current.eliteSpawned) {
                isElite = true;
                waveState.current.eliteSpawned = true; 
                addNotification("⚠️ ELITE SQUAD DETECTED", COLORS.enemyElite, 'BOSS');
            } else if (wave % 5 === 0 && wave % 10 !== 0 && r > 0.95) {
                isElite = true;
            }

            if (isBoss) {
                enemy.type = 2; 
                enemy.health = (2000 + (level * 250) + (wave * 100)) * hpMult * globalHpReduction;
                enemy.speed = (3 + (level * 0.1)) * speedMult;
                enemy.radius = 2.5;
                enemy.scale = 3.0; 
                setBossData({ hp: enemy.health, maxHp: enemy.health });
            } else if (isElite) {
                enemy.type = 1; 
                enemy.health = (150 + (level * 20)) * hpMult * globalHpReduction;
                enemy.speed = (4 + (level * 0.1)) * speedMult;
                enemy.radius = 1.5;
                enemy.scale = 1.5; 
            } else if (wave >= 3 && r > 0.85) {
                enemy.type = 3; 
                enemy.health = (15 + (level * 5)) * hpMult * globalHpReduction;
                enemy.speed = 3.0 * speedMult;
                enemy.radius = 0.8;
                enemy.scale = 1.0; 
            } else if (wave >= 2 && r > 0.70) {
                enemy.type = 1; 
                enemy.health = (25 + (level * 8)) * hpMult * globalHpReduction;
                enemy.speed = (3.5 + (level * 0.1)) * speedMult;
                enemy.radius = 1.0;
                enemy.scale = 1.2;
            } else {
                enemy.type = 0; 
                enemy.health = (10 + (level * 4)) * hpMult * globalHpReduction;
                enemy.speed = (4 + (level * 0.15)) * speedMult;
                enemy.radius = 0.6;
                enemy.scale = 1.0;
            }
            enemy.maxHealth = enemy.health;
        }
    }

    // 2. DoT Ticker (Every 0.5s)
    dotTicker.current += delta;
    const shouldTickDoT = dotTicker.current > 0.5;
    if (shouldTickDoT) dotTicker.current = 0;

    const time = state.clock.getElapsedTime();

    // 3. Main Loop
    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {

            // OPTIMIZATION: Register to Grid
            spatialGrid.current.add(i, e.position.x, e.position.z);

            const distToPlayer = e.position.distanceTo(playerPosition);
            let currentSpeed = e.speed;
            let canMove = true;

            // Update Boss HP on UI
            if (e.type === 2) {
                 const currentBossData = useGameStore.getState().bossData;
                 if (Math.abs(currentBossData.hp - e.health) > 5) {
                     setBossData({ hp: e.health });
                 }
            }

            // Burn
            if (e.burnTimer && e.burnTimer > 0) {
                e.burnTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.burnDamage || 5) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { 
                        detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'FIRE' } 
                    }));
                }
            }
            // Poison
            if (e.poisonTimer && e.poisonTimer > 0) {
                e.poisonTimer -= delta;
                if (shouldTickDoT) {
                    const dmg = (e.poisonDamage || 3) * 0.5;
                    e.health -= dmg;
                    window.dispatchEvent(new CustomEvent('damage', { 
                        detail: { position: e.position, damage: dmg, isDoT: true, damageType: 'POISON' } 
                    }));
                }
            }

            // Freeze
            if (e.freezeTimer && e.freezeTimer > 0) {
                e.freezeTimer -= delta;
                canMove = false;
                if (stunIconsRef.current) {
                    dummy.position.copy(e.position).add(tempVec.set(0, (e.scale * 1.8) + 0.5, 0)); 
                    dummy.rotation.set(time * 5, time * 3, 0);
                    dummy.scale.set(0.5, 0.5, 0.5);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                } 
            } else {
                if (stunIconsRef.current) {
                    dummy.position.set(0, -100, 0);
                    dummy.updateMatrix();
                    stunIconsRef.current.setMatrixAt(i, dummy.matrix);
                }
            }

            // Slow
            if (e.slowTimer && e.slowTimer > 0) {
                e.slowTimer -= delta;
                currentSpeed *= (1 - (e.slowFactor || 0.5));
            }

            // --- COLOR LOGIC ---
            if (e.freezeTimer && e.freezeTimer > 0) tempColor.set('#3b82f6');
            else if (e.burnTimer && e.burnTimer > 0) tempColor.set('#ef4444');
            else {
                if (e.type === 2) tempColor.set(COLORS.enemyBoss);
                else if (e.type === 3) tempColor.set(COLORS.enemyShooter);
                else if (e.type === 1) {
                     if (e.scale > 1.4) tempColor.set(COLORS.enemyElite);
                     else tempColor.set(COLORS.enemyOrc);
                }
                else tempColor.set(COLORS.enemySlime);

                if (e.poisonTimer && e.poisonTimer > 0) tempColor.lerp(new Color('#4ade80'), 0.5);
            }

            meshRef.current.setColorAt(i, tempColor);

            // AI Movement
            if (canMove) {
                let moved = false;
                // Check Blackhole
                for(let b=0; b < activeBullets.length; b++) {
                    const bullet = activeBullets[b];
                    if (bullet.active && bullet.type === 'BLACKHOLE') {
                        const max = bullet.maxPullCount || 8;
                        const current = bullet.currentPullCount || 0;
                        if (current < max) {
                            const distToBH = e.position.distanceTo(bullet.position);
                            if (distToBH < 15.0) {
                                pushDir.subVectors(bullet.position, e.position).normalize();
                                e.position.add(pushDir.multiplyScalar(currentSpeed * 2.0 * delta));
                                moved = true;
                                bullet.currentPullCount = current + 1;
                            }
                        }
                    }
                }

                if (earthwall.active) {
                    const distToWall = e.position.distanceTo(earthwall.position);
                    const collisionDist = earthwall.radius + e.radius;
                    if (distToWall < collisionDist) {
                        pushDir.subVectors(e.position, earthwall.position).normalize();
                        if (pushDir.lengthSq() === 0) pushDir.set(1, 0, 0);
                        e.position.copy(earthwall.position).add(pushDir.multiplyScalar(collisionDist));
                        moved = true; 
                    }
                }

                if (!moved) {
                    const nextPos = e.position.clone();
                    if (e.type === 3 && distToPlayer > 15) { 
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    } else if (e.type !== 3) {
                         tempVec.subVectors(playerPosition, e.position).normalize();
                         nextPos.add(tempVec.multiplyScalar(currentSpeed * delta));
                    }

                    // Obstacle Collision
                    for(const obs of obstacles) {
                        const distToObs = nextPos.distanceTo(obs.position);
                        const minDist = obs.radius + e.radius;
                        if (distToObs < minDist) {
                            pushDir.subVectors(nextPos, obs.position).normalize();
                            nextPos.copy(obs.position).add(pushDir.multiplyScalar(minDist));
                        }
                    }
                    e.position.copy(nextPos);
                }
            }

            // Shooter Firing Logic
            if (e.type === 3 && canMove) {
                e.stateTimer = (e.stateTimer || 0) + delta;
                if (e.stateTimer > 2.0 && distToPlayer < 25) {
                    e.stateTimer = 0;
                    const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 3.0;
                        bullet.position.copy(e.position).add(tempVec.set(0, 1, 0)); 
                        pushDir.subVectors(playerPosition, e.position).normalize();
                        bullet.velocity.copy(pushDir).multiplyScalar(15);
                    }
                }
            }

            // Player Collision Damage
            if (e.type !== 3 && distToPlayer < e.radius + 0.5 && canMove) {
                const dmg = (e.type === 2 ? 30 : 10) * (1 + wave * 0.1); 
                takeDamage(dmg * delta);

                // Return Damage (Thorns) Logic
                if (stats.returnDamage > 0) {
                    const thornDmg = stats.returnDamage * delta; // continuous damage
                    e.health -= thornDmg;
                    if (shouldTickDoT) {
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: e.position, damage: stats.returnDamage, isCrit: false, damageType: 'PHYSICAL', isDoT: true } 
                        }));
                    }
                }
            }

            // Death Logic
            if (e.health <= 0) {
                e.active = false;

                let goldDrops = 0;
                if (e.type === 2) goldDrops = 5; 
                else if (e.scale > 1.5) goldDrops = 3; 
                else if (Math.random() < 0.5) goldDrops = 1; 

                for(let g=0; g<goldDrops; g++) {
                    const offset = tempVec.set((Math.random()-0.5), 0, (Math.random()-0.5));
                    spawnDrop(e.position.clone().add(offset), 'GOLD', 10);
                }

                addScore(0); 

                if (e.type === 2) { 
                    setBossData({ active: false });
                    const roll = Math.random();
                    let dropped = false;
                    if (wave >= 60 && roll < Math.min(0.20, (wave - 50) * 0.01)) {
                        spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); dropped = true;
                    }
                    if (!dropped && wave >= 30 && Math.random() < Math.min(0.50, (wave - 20) * 0.02)) {
                        spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); dropped = true;
                    }
                    if (!dropped) spawnDrop(e.position, 'ITEM', 0, 'EPIC');
                    spawnDrop(e.position.clone().add(tempVec.set(1,0,0)), 'XP', 1000); 
                } 
                else if (e.scale > 1.5) { 
                     if (Math.random() > 0.5) spawnDrop(e.position, 'ITEM', 0); 
                     for(let k=0; k<5; k++) {
                         const offset = tempVec.set((Math.random()-0.5)*2, 0, (Math.random()-0.5)*2);
                         spawnDrop(e.position.clone().add(offset), 'XP', 100);
                     }
                }
                else {
                    if (Math.random() > 0.90) spawnDrop(e.position, 'ITEM', 0);
                    else spawnDrop(e.position, 'XP', e.type === 3 ? 30 : 20);
                }
                dummy.position.set(0, -100, 0);
                if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
            } else {
                dummy.position.copy(e.position);
                const aestheticHeight = 2.0; 
                const aestheticWidth = 0.6;

                if (e.type === 0 && e.scale < 0.9) {
                    dummy.scale.set(e.scale, e.scale * 0.5, e.scale); 
                } else {
                    dummy.scale.set(e.scale * aestheticWidth, e.scale * aestheticHeight, e.scale * aestheticWidth);
                }

                const totalHeight = 1.0 * dummy.scale.y;
                if (e.type !== 2) {
                    const bob = Math.abs(Math.sin(state.clock.elapsedTime * 5 + i)) * 0.2;
                    dummy.position.y = (totalHeight / 2) + bob;
                } else {
                    dummy.position.y = totalHeight / 2;
                }
                dummy.lookAt(playerPosition);
            }
        } else {
            dummy.position.set(0, -100, 0);
            if (stunIconsRef.current) stunIconsRef.current.setMatrixAt(i, dummy.matrix);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    if (stunIconsRef.current) stunIconsRef.current.instanceMatrix.needsUpdate = true;

    minimapThrottle.current += 1;
    if (minimapThrottle.current > 10) {
        minimapThrottle.current = 0;
        const activeEnemies = enemies.current.filter(e => e.active).map(e => ({ x: e.position.x, z: e.position.z, type: e.type }));
        updateMinimapEnemies(activeEnemies);
    }
  });

  return (
    <>
        <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <boxGeometry args={[1, 1, 1]} />
            <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
        </instancedMesh>
        <instancedMesh ref={stunIconsRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <torusGeometry args={[0.5, 0.1, 8, 16]} />
            <meshBasicMaterial color="#facc15" />
        </instancedMesh>
    </>
  );
};

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage, BufferGeometry, Color, InstancedBufferAttribute } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus, BulletData, ProjectileType, EnemyData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface BulletManagerProps {
  playerPos: Vector3;
  targetPosRef: React.MutableRefObject<Vector3>;
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  projectileType?: ProjectileType;
  // New Props via Player
  enemiesDataRef?: React.MutableRefObject<EnemyData[]>;
}

const dummy = new Object3D();
const tempColor = new Color();

export const BulletManager: React.FC<BulletManagerProps & { spatialGrid?: React.MutableRefObject<SpatialHashGrid> }> = ({ playerPos, targetPosRef, bulletsDataRef, projectileType = 'MAGIC', enemiesDataRef, spatialGrid }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { stats, status, equipment, obstacles, heal } = useGameStore();
  const { scene } = useThree();

  const bullets = useRef(new Array(MAX_BULLETS).fill(0).map((_, i) => ({
    id: i,
    active: false,
    position: new Vector3(),
    velocity: new Vector3(),
    lifetime: 0,
    type: 'MAGIC' as ProjectileType,
    state: 0,
    pierce: 1,
    hitIds: [] as number[],
    effect: undefined,
    knockback: 0,
    trailTimer: 0,
    damageMultiplier: 1,
    bouncesLeft: 0,
  })));

  const lastShot = useRef(0);

  useEffect(() => {
    bulletsDataRef.current = bullets.current;
  }, [bulletsDataRef]);

  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
        const colors = new Float32Array(MAX_BULLETS * 3);
        for(let i=0; i<MAX_BULLETS; i++) {
            tempColor.set('#000000');
            tempColor.toArray(colors, i*3);
        }
        meshRef.current.geometry.setAttribute('color', new InstancedBufferAttribute(colors, 3));
    }
  }, [projectileType]); 

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();

    // 1. Auto-Fire Logic
    const fireInterval = 1 / stats.fireRate;
    const targetPos = targetPosRef.current;

    if (targetPos && time - lastShot.current > fireInterval) {
      lastShot.current = time;
      const dir = new Vector3().subVectors(targetPos, playerPos).normalize();
      const count = Math.min(7, stats.multishot); 

      // Double Cast Logic: Chance to run the loop twice
      const castLoops = Math.random() < stats.doubleCastChance ? 2 : 1;

      for (let c = 0; c < castLoops; c++) {
          for (let i = 0; i < count; i++) {
            const bullet = bullets.current.find(b => !b.active);
            if (bullet) {
                bullet.active = true;
                bullet.lifetime = projectileType === 'AXE' ? 3.5 : 3.0; 
                bullet.position.copy(playerPos).add(new Vector3(0, 1, 0));
                bullet.type = projectileType;
                bullet.state = 0;
                bullet.hitIds = [];
                bullet.knockback = stats.knockback;
                bullet.damageMultiplier = 1; 
                bullet.bouncesLeft = 0;

                if (equipment.weapon && equipment.weapon.onHitEffect) {
                    bullet.effect = { ...equipment.weapon.onHitEffect };
                    if (bullet.effect.type === 'BURN' || bullet.effect.type === 'POISON') {
                        bullet.effect.value = stats.damage * 0.3;
                    }
                } else {
                    bullet.effect = undefined;
                }

                bullet.pierce = projectileType === 'AXE' ? 99 : 1; 
                if (projectileType === 'MAGIC') bullet.pierce = 4;
                if (projectileType === 'ICE') bullet.pierce = 2; 

                let offsetIndex = 0;
                if (i > 0) {
                    const pair = Math.ceil(i / 2);
                    const sign = i % 2 !== 0 ? 1 : -1;
                    offsetIndex = pair * sign;
                }

                if (projectileType === 'AXE') {
                    const offsetDist = offsetIndex * 2.0; 
                    bullet.position.add(dir.clone().cross(new Vector3(0,1,0)).multiplyScalar(offsetDist));
                    bullet.velocity.copy(dir); 
                } else {
                    const angle = offsetIndex * stats.spread;
                    // Slightly perturb angle for 2nd cast to avoid direct overlap
                    const variance = c > 0 ? (Math.random()-0.5)*0.1 : 0;
                    const spreadDir = dir.clone().applyAxisAngle(new Vector3(0, 1, 0), angle + variance);
                    bullet.velocity.copy(spreadDir);
                }

                let speed = stats.projectileSpeed;
                if (projectileType === 'AXE') speed *= 1.8; 
                if (projectileType === 'MAGIC') speed *= 0.6; 
                if (projectileType === 'ARROW') speed *= 1.5; 

                bullet.velocity.multiplyScalar(speed);
            }
          }
      }
    }

    // 2. Bullet Update Logic
    // OPTIMIZATION: Retrieve enemies reference
    const enemies = enemiesDataRef ? enemiesDataRef.current : [];
    const grid = spatialGrid ? spatialGrid.current : null;

    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets.current[i];
        if (b.active) {

            // Movement Logic
            if (b.type === 'FIREBALL') {
                b.position.add(b.velocity.clone().multiplyScalar(delta));
                b.trailTimer = (b.trailTimer || 0) - delta;
                if (b.trailTimer <= 0) {
                    b.trailTimer = 0.1; 
                    const trail = bullets.current.find(t => !t.active);
                    if (trail) {
                        trail.active = true;
                        trail.type = 'FIRE_TRAIL';
                        trail.lifetime = 5.0; 
                        trail.position.copy(b.position);
                        trail.position.y = 0.1; 
                        trail.velocity.set(0, 0, 0); 
                        trail.pierce = 9999; 
                        trail.damageMultiplier = 0.5;
                        trail.effect = undefined;
                    }
                }
            } else if (b.type === 'BLACKHOLE') {
                b.rotation = (b.rotation || 0) + delta * 2;
            } else if (b.type === 'STORM') {
                b.position.add(b.velocity.clone().multiplyScalar(delta));
                b.rotation = (b.rotation || 0) + delta * 15; 
            } else if (b.type === 'FIRE_TRAIL') {
                // Stationary
            } else if (b.type === 'AXE') {
                if (b.state === 0) {
                    b.velocity.multiplyScalar(0.95); 
                    if (b.velocity.length() < 2) {
                        b.state = 1; 
                        b.hitIds = []; 
                    }
                } else {
                    const toPlayer = new Vector3().subVectors(playerPos, b.position).normalize();
                    b.velocity.add(toPlayer.multiplyScalar(50 * delta)); 
                    if (b.position.distanceTo(playerPos) < 1.5) {
                        b.active = false;
                    }
                }
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            } else {
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            }

            b.lifetime -= delta;

            if (b.active && b.type !== 'FIRE_TRAIL' && b.type !== 'BLACKHOLE' && b.type !== 'STORM') { 
                for (const obs of obstacles) {
                    if (b.position.distanceTo(obs.position) < obs.radius + 0.3) {
                        b.active = false;
                        b.lifetime = 0;
                        break;
                    }
                }
            }

            if (b.lifetime <= 0) {
                // Explosion Logic (Blackhole end)
                 if (b.type === 'BLACKHOLE' && enemies) {
                     // Need broad phase for explosion too? Yes ideally.
                     const nearbyIds = grid ? grid.query(b.position.x, b.position.z) : [];
                     const idsToCheck = grid ? nearbyIds : enemies.map(e => e.id);

                     for(const id of idsToCheck) {
                         const e = enemies[id];
                         if (e.active && e.position.distanceTo(b.position) < 8.0) {
                                const dmg = stats.damage * 5.0; 
                                e.health -= dmg;
                                window.dispatchEvent(new CustomEvent('damage', { 
                                    detail: { position: e.position, damage: dmg, isCrit: false, damageType: 'MAGIC' } 
                                }));
                         }
                     }
                }
                b.active = false;
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);

                // --- COLLISION DETECTION (OPTIMIZED) ---
                if (enemies && grid && b.type !== 'BLACKHOLE') { // Blackhole handles pull in EnemyManager, dmg at end
                    // Query Grid
                    const candidateIds = grid.query(b.position.x, b.position.z);

                    const baseDamage = stats.damage;
                    const critRate = stats.critRate;
                    const critDamage = stats.critDamage;

                    for(const id of candidateIds) {
                        if (!b.active) break; // Bullet died mid-loop

                        const e = enemies[id];
                        if (!e.active) continue;
                        if (b.hitIds && b.hitIds.includes(e.id)) continue;

                        // Precise Check
                        let hitRadius = e.radius + 1.5; 
                        if (b.type === 'MAGIC') hitRadius += 1.0;
                        if (b.type === 'FIREBALL') hitRadius += 2.0; 
                        if (b.type === 'FIRE_TRAIL') hitRadius = e.radius + 1.5; 
                        if (b.type === 'BURNING_ARROW') hitRadius += 1.5; 
                        if (b.type === 'FREEZING_ARROW') hitRadius += 1.5; 
                        if (b.type === 'PIERCING_ARROW') hitRadius += 4.0;
                        if (b.type === 'STORM') hitRadius += 4.0;

                        if (b.position.distanceTo(e.position) < hitRadius) {

                             // Fire Trail Logic
                             if (b.type === 'FIRE_TRAIL') {
                                e.burnTimer = 2.0;
                                e.burnDamage = 5;
                                e.health -= 2 * delta; 
                                continue; 
                            }

                            const isCrit = Math.random() < critRate;
                            let dmg = (isCrit ? baseDamage * critDamage : baseDamage);
                            if (b.damageMultiplier) dmg *= b.damageMultiplier;

                            // Effects
                            if (b.effect) {
                                const { type, duration, value, chance } = b.effect;
                                if (Math.random() < (chance || 1.0)) {
                                    if (type === 'BURN') { e.burnTimer = duration; e.burnDamage = value ?? 5; }
                                    if (type === 'POISON') { e.poisonTimer = duration; e.poisonDamage = value ?? 3; }
                                    if (type === 'STUN' || type === 'FREEZE') { e.freezeTimer = duration; }
                                    if (type === 'SLOW') { e.slowTimer = duration; e.slowFactor = value || 0.5; }
                                }
                            }

                            let dmgType = 'PHYSICAL';
                            if (b.type === 'FIREBALL' || b.type === 'BURNING_ARROW' || b.type === 'FIRE_TRAIL') dmgType = 'FIRE';
                            else if (b.type === 'FREEZING_ARROW' || b.type === 'ICE') dmgType = 'ICE';
                            else if (b.type === 'MAGIC') dmgType = 'MAGIC';
                            else if (b.type === 'STORM') dmgType = 'MAGIC';

                            // AOE Logic
                            if (b.type === 'MAGIC' || b.type === 'FIREBALL' || b.type === 'BURNING_ARROW' || b.type === 'FREEZING_ARROW') {
                                // For AOE, we can re-query grid or check neighbors of current target
                                // Simple: Check neighbors of 'e'
                                const aoeRange = b.type === 'MAGIC' ? 4.0 : 5.0;
                                const aoeCandidates = grid.query(e.position.x, e.position.z);
                                for(const aoeId of aoeCandidates) {
                                    const neighbor = enemies[aoeId];
                                    if(neighbor.active && neighbor.id !== e.id && neighbor.position.distanceTo(e.position) < aoeRange) {
                                        neighbor.health -= dmg * 0.5;
                                        if (b.type === 'BURNING_ARROW') { neighbor.burnTimer = 4.0; neighbor.burnDamage = baseDamage * 0.5; }
                                        if (b.type === 'FREEZING_ARROW') { neighbor.freezeTimer = 1.5; }
                                    }
                                }
                            }

                            // Apply to main target
                            if (b.type === 'BURNING_ARROW') { e.burnTimer = 4.0; e.burnDamage = baseDamage * 0.5; }
                            if (b.type === 'FREEZING_ARROW') { e.freezeTimer = 1.5; }
                            if (b.type === 'FIREBALL') { e.burnTimer = 3.0; e.burnDamage = 5; }

                            e.health -= dmg;

                            // LIFE STEAL LOGIC
                            if (stats.lifeSteal > 0) {
                                const healAmt = dmg * stats.lifeSteal;
                                heal(healAmt);
                            }

                            window.dispatchEvent(new CustomEvent('damage', { 
                                detail: { position: e.position, damage: dmg, isCrit, damageType: dmgType } 
                            }));

                            if (b.hitIds) b.hitIds.push(e.id);

                            // Knockback
                            if (e.type !== 2 && e.freezeTimer <= 0) { // Can move check simplified
                                const kbDir = e.position.clone().sub(b.position).normalize();
                                const kbForce = b.knockback ?? 0.5;
                                e.position.add(kbDir.multiplyScalar(kbForce));
                            }

                            // Bouncing
                            if (b.type === 'STORM' && b.bouncesLeft && b.bouncesLeft > 0) {
                                b.bouncesLeft--;
                                let nearestDist = 50; 
                                let nextTargetPos = null;
                                // Simplified bounce: Check current candidate list
                                for(const nextId of candidateIds) {
                                    const potential = enemies[nextId];
                                    if (potential.active && !b.hitIds.includes(potential.id)) {
                                        const d = potential.position.distanceTo(e.position);
                                        if (d < nearestDist) {
                                            nearestDist = d;
                                            nextTargetPos = potential.position;
                                        }
                                    }
                                }
                                if (nextTargetPos) {
                                    const newDir = new Vector3().subVectors(nextTargetPos, e.position).normalize();
                                    b.velocity.copy(newDir).multiplyScalar(15);
                                    b.position.copy(e.position).add(newDir.multiplyScalar(1.0));
                                } else {
                                    b.active = false;
                                }
                            } else if (b.pierce && b.pierce > 0) {
                                b.pierce--;
                                if (b.pierce <= 0) b.active = false;
                            } else {
                                b.active = false;
                            }
                        }
                    }
                }


                // Visuals
                if (b.type === 'AXE') {
                     dummy.rotation.set(0, time * 25, 0); 
                     dummy.scale.set(2.5, 2.5, 2.5); 
                     tempColor.set('#ef4444');
                } else if (b.type === 'MAGIC') {
                     dummy.rotation.set(time, time, time);
                     dummy.scale.set(2, 2, 2); 
                     tempColor.set(COLORS.bulletPlayer);
                } else if (b.type === 'ICE') {
                     dummy.rotation.set(time, 0, time);
                     dummy.scale.set(1.5, 1.5, 1.5);
                     tempColor.set('#a5f3fc');
                } else if (b.type === 'BLACKHOLE') {
                     dummy.rotation.set(time*5, time*2, 0);
                     dummy.scale.set(8, 8, 8); 
                     tempColor.set('#000000'); 
                } else if (b.type === 'STORM') {
                     dummy.rotation.set(0, b.rotation || 0, 0);
                     dummy.scale.set(5, 5, 5); 
                     tempColor.set('#818cf8'); 
                } else if (b.type === 'FIREBALL') {
                     dummy.rotation.set(time*2, time*2, time*2);
                     dummy.scale.set(12, 12, 12); 
                     tempColor.set('#ff0000'); 
                } else if (b.type === 'FIRE_TRAIL') {
                     dummy.rotation.set(0, time, 0);
                     dummy.scale.set(12, 0.2, 12); 
                     tempColor.set('#f97316'); 
                } else if (b.type === 'PIERCING_ARROW') {
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(6, 6, 15); 
                     tempColor.set('#0ea5e9');
                } else if (b.type === 'BURNING_ARROW') {
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(3, 3, 3);
                     tempColor.set('#ef4444');
                } else if (b.type === 'FREEZING_ARROW') {
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(3, 3, 3);
                     tempColor.set('#0ea5e9'); 
                } else {
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(1, 1, 1);
                     tempColor.set('#22c55e');
                }
            }
        } else {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
        meshRef.current.setColorAt(i, tempColor);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  });

  const onGeometryUpdate = (geo: BufferGeometry) => {
      if ((projectileType === 'ARROW' || projectileType === 'PIERCING_ARROW' || projectileType === 'BURNING_ARROW' || projectileType === 'FREEZING_ARROW') && geo) {
          geo.rotateX(Math.PI / 2); 
      }
  };

  return (
    <instancedMesh key={projectileType} ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      {(projectileType?.includes('ARROW')) && <cylinderGeometry args={[0.05, 0.05, 1.5, 6]} ref={onGeometryUpdate} />}
      {projectileType === 'AXE' && <boxGeometry args={[1, 0.1, 1]} />}
      {projectileType === 'STORM' && <coneGeometry args={[0.5, 2, 8, 1, true]} />} 
      {(!projectileType?.includes('ARROW') && projectileType !== 'AXE' && projectileType !== 'STORM') && <dodecahedronGeometry args={[0.3, 0]} />} 

      <meshStandardMaterial 
        vertexColors
        emissive={projectileType === 'MAGIC' || projectileType === 'FIRE_TRAIL' || projectileType === 'PIERCING_ARROW' ? (projectileType === 'PIERCING_ARROW' ? '#0ea5e9' : COLORS.bulletPlayer) : '#000'} 
        emissiveIntensity={projectileType === 'BLACKHOLE' ? 0 : (projectileType === 'MAGIC' || projectileType === 'FIRE_TRAIL' || projectileType === 'PIERCING_ARROW' ? 2 : 0)} 
        transparent={true}
        opacity={projectileType === 'BLACKHOLE' ? 0.9 : (projectileType === 'STORM' ? 0.5 : (projectileType === 'MAGIC' || projectileType === 'FIRE_TRAIL' ? 0.6 : 1.0))}
        depthWrite={projectileType !== 'STORM'}
        side={projectileType === 'STORM' ? 2 : 0}
      />
    </instancedMesh>
  );
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { useGameStore, calculateItemCP, calculateTotalCP } from '../store';
import { GameStatus, Upgrade, Item, Rarity, GameNotification, HeroClass, SkillLevels, ActionResult, PlayerStats } from '../types';
import { UPGRADES_POOL, ITEMS_POOL, HERO_STATS, PETS_POOL, SKILLS_INFO, ARENA_SIZE, SHOP_POSITIONS } from '../constants';
import { 
  Heart, Zap, Sparkles, RotateCcw, 
  Backpack, Shield, Sword, Gem, X, User, Flame, Wind, ShoppingBag, Coins, Hammer, MoveRight, Activity, Magnet, Ghost, Dices, Timer, Trash2, CheckCircle2, ShieldCheck, Wand, FlaskConical, CircleDollarSign, Package,
  Crosshair, Axe, Wand2, Hexagon, Layers, BookOpen, Star, ArrowUpCircle, Trophy, RefreshCcw, Anvil, ArrowRight, Sun, Tornado, Skull, Check, AlertTriangle, Book, Search, Lock
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

// --- HELPER COMPONENTS ---

const ItemIcon: React.FC<{ item: Item; size?: number }> = ({ item, size = 24 }) => {
  if (item.type === 'POTION') return <FlaskConical size={size} className="text-red-400" />;
  if (item.type === 'CORE') return <Hexagon size={size} className="text-blue-400" />;
  if (item.type === 'REVIVE') {
      if (item.id.includes('gem')) return <Gem size={size} className="text-green-400" />;
      return <Heart size={size} className="text-yellow-500" fill="rgba(234, 179, 8, 0.5)" />;
  }
  if (item.type === 'WEAPON') {
      if (item.projectileType === 'MAGIC') return <Wand2 size={size} className="text-purple-400" />;
      if (item.projectileType === 'ARROW') return <Crosshair size={size} className="text-green-400" />;
      if (item.projectileType === 'AXE') return <Axe size={size} className="text-red-400" />;
      return <Sword size={size} className="text-slate-300" />;
  }
  if (item.type === 'ARMOR') return <Shield size={size} className="text-blue-300" />;
