const Minimap: React.FC = () => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const { playerPosition, minimapEnemies } = useGameStore();

    useEffect(() => {
        let animationFrameId: number;
        const ctx = canvasRef.current?.getContext('2d');

        const render = () => {
            if (!ctx || !canvasRef.current) return;
            const width = canvasRef.current.width;
            const height = canvasRef.current.height;
            const scale = width / ARENA_SIZE; 
            const center = width / 2;

            // Clear
            ctx.fillStyle = 'rgba(15, 23, 42, 0.8)'; // slate-900/80
            ctx.clearRect(0, 0, width, height);
            ctx.fillRect(0, 0, width, height);

            // Draw Border
            ctx.strokeStyle = '#334155';
            ctx.lineWidth = 2;
            ctx.strokeRect(0, 0, width, height);

            // Function to map World Coords to Canvas Coords
            const mapX = (x: number) => center + x * scale;
            const mapY = (z: number) => center + z * scale;

            // Draw Shops
            SHOP_POSITIONS.forEach(shop => {
                const x = mapX(shop.position[0]);
                const y = mapY(shop.position[2]);
                ctx.fillStyle = shop.color;
                ctx.fillRect(x - 2, y - 2, 4, 4);
            });

            // Draw Enemies (Red Dots)
            // Use snapshot from store to avoid reading deep ref
            minimapEnemies.forEach(e => {
                const x = mapX(e.x);
                const y = mapY(e.z);
                if (x > 0 && x < width && y > 0 && y < height) {
                    ctx.fillStyle = e.type === 2 ? '#ef4444' : '#f87171'; // Darker red for boss
                    ctx.beginPath();
                    ctx.arc(x, y, e.type === 2 ? 3 : 1.5, 0, Math.PI * 2);
                    ctx.fill();
                }
            });

            // Draw Player (Blue Arrow)
            const px = mapX(playerPosition.x);
            const py = mapY(playerPosition.z);
            ctx.fillStyle = '#3b82f6';
            ctx.beginPath();
            ctx.arc(px, py, 4, 0, Math.PI * 2);
            ctx.fill();

            // Draw Player Direction (Optional visual flair)
            ctx.beginPath();
            ctx.moveTo(px, py - 6);
            ctx.lineTo(px - 3, py + 2);
            ctx.lineTo(px + 3, py + 2);
            ctx.fill();

            animationFrameId = requestAnimationFrame(render);
        };

        render();
        return () => cancelAnimationFrame(animationFrameId);
    }, [playerPosition, minimapEnemies]); 

    return (
        <div className="absolute bottom-6 right-6 z-20 pointer-events-none">
            <canvas ref={canvasRef} width={200} height={200} className="rounded-full border-4 border-slate-700 shadow-2xl bg-slate-900/80" />
        </div>
    );
};

