                                    <div className="flex-1 overflow-y-auto bg-slate-900/30 rounded p-2 custom-scrollbar">
                                        <div className="grid grid-cols-5 gap-2">
                                            {inventory.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE').map((item, idx) => (
                                                <button 
                                                    key={idx} 
                                                    onClick={() => setSelectedUpgradeItem(item)}
                                                    onMouseEnter={() => setHoveredItem(item)}
                                                    onMouseLeave={() => setHoveredItem(null)}
                                                    className={`aspect-square bg-slate-800 border-2 rounded flex items-center justify-center relative ${selectedUpgradeItem === item ? 'border-red-500 bg-red-900/20' : 'border-slate-600 hover:border-slate-400'}`}
                                                >
                                                    <ItemIcon item={item} size={16} />
                                                    {item.level > 1 && <div className="absolute top-0 right-0 text-[10px] font-bold text-yellow-500">+{item.level-1}</div>}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                    {selectedUpgradeItem ? (
                                        <div className="bg-slate-800 p-4 rounded border border-slate-600 flex flex-col gap-2">
                                            <div className="flex justify-between items-start">
                                                <div>
                                                    <div className="font-bold text-sm text-white">{selectedUpgradeItem.name} <span className="text-yellow-400">+{selectedUpgradeItem.level-1}</span></div>
                                                    <div className="text-[10px] text-slate-400">Current CP: {calculateItemCP(selectedUpgradeItem)}</div>
                                                </div>
                                            </div>
                                            <div className="h-px bg-slate-700 w-full my-1" />
                                            <div className="flex justify-between items-center">
                                                <div className="text-xs text-slate-300">Cost:</div>
                                                <div className="flex gap-3 text-xs font-mono font-bold">
                                                    <span className="text-yellow-400">{Math.floor(selectedUpgradeItem.price * selectedUpgradeItem.level * 0.5)} G</span>
                                                    <span className="text-blue-400">{Math.ceil(selectedUpgradeItem.level / 2)} Cores</span>
                                                </div>
                                            </div>
                                            <div className="flex justify-between items-center text-xs">
                                                <span className="text-slate-400">Success Rate:</span>
                                                <span className={`font-bold ${selectedUpgradeItem.level >= 3 ? (Math.max(10, 100 - ((selectedUpgradeItem.level - 2) * 10)) > 50 ? 'text-green-400' : 'text-red-400') : 'text-green-400'}`}>
                                                    {selectedUpgradeItem.level < 3 ? '100%' : `${Math.max(10, 100 - ((selectedUpgradeItem.level - 2) * 10))}%`}
                                                </span>
                                            </div>
                                            <div className="bg-slate-900/50 p-2 rounded text-[10px] grid grid-cols-2 gap-x-2 gap-y-1 mt-1 border border-slate-700">
                                                {selectedUpgradeItem.stats && Object.entries(selectedUpgradeItem.stats).map(([k, v]) => {
                                                    const key = k as keyof PlayerStats;
                                                    const val = v as number;
                                                    const lvl = Math.max(1, selectedUpgradeItem.level);
                                                    const base = val / lvl;
                                                    const nextVal = parseFloat((base * (lvl + 1)).toFixed(2));
                                                    return (
                                                        <div key={k} className="flex justify-between items-center col-span-2">
                                                            <span className="text-slate-400 capitalize">{key.replace(/([A-Z])/g, ' $1')}</span>
                                                            <div className="flex gap-2 font-mono">
                                                                <span className="text-slate-200">{val}</span>
                                                                <span className="text-slate-500">→</span>
                                                                <span className="text-green-400">{nextVal}</span>
                                                            </div>
                                                        </div>
                                                    );
                                                })}
                                            </div>
                                            <button 
                                                onClick={() => {
                                                    const res = upgradeItem(selectedUpgradeItem);
                                                    if (res.success && res.newItem) {
                                                        setSelectedUpgradeItem(res.newItem);
                                                    }
                                                }}
                                                disabled={selectedUpgradeItem.level >= 10}
                                                className={`w-full font-bold py-2 rounded mt-1 flex items-center justify-center gap-2 ${selectedUpgradeItem.level >= 10 ? 'bg-slate-700 text-slate-500 cursor-not-allowed' : 'bg-red-600 hover:bg-red-500 text-white'}`}
                                            >
                                                {selectedUpgradeItem.level >= 10 ? 'MAX LEVEL' : <><Hammer size={16} /> UPGRADE</>}
                                            </button>
                                        </div>
                                    ) : (
                                        <div className="h-32 flex items-center justify-center text-slate-500 text-sm bg-slate-900/50 rounded">Select Item</div>
                                    )}
                                </div>
                            )}

                            {/* RECYCLE AND CRAFT TABS */}
                            {blacksmithTab === 'RECYCLE' && (
                                <div className="flex flex-col gap-4 h-full">
                                    {/* Recycling UI code... */}
                                    <div className="flex flex-col gap-1 items-center bg-slate-900/50 p-3 rounded text-center">
                                        <div className="text-xs font-bold text-slate-400 uppercase">Materials Storage</div>
                                        <div className="flex gap-4 text-xs items-center">
                                            <div className="flex flex-col items-center"><div className="w-3 h-3 rounded-full bg-slate-200 mb-1"/>{materials.COMMON}</div>
                                            <div className="flex flex-col items-center"><div className="w-3 h-3 rounded-full bg-blue-400 mb-1"/>{materials.RARE}</div>
                                            <div className="flex flex-col items-center"><div className="w-3 h-3 rounded-full bg-purple-400 mb-1"/>{materials.EPIC}</div>
                                            <div className="flex flex-col items-center"><div className="w-3 h-3 rounded-full bg-yellow-400 mb-1"/>{materials.LEGENDARY}</div>
                                            <div className="flex flex-col items-center"><div className="w-3 h-3 rounded-full bg-red-500 mb-1"/>{materials.MYTHIC}</div>
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-3 gap-2">
                                        <button onClick={() => massRecycle('COMMON')} className="bg-slate-700 hover:bg-slate-600 text-xs py-2 rounded text-slate-200">Recycle All Common</button>
                                        <button onClick={() => massRecycle('RARE')} className="bg-blue-900 hover:bg-blue-800 text-xs py-2 rounded text-blue-200">Recycle All Rare</button>
                                        <button onClick={() => massRecycle('EPIC')} className="bg-purple-900 hover:bg-purple-800 text-xs py-2 rounded text-purple-200">Recycle All Epic</button>
                                    </div>
                                    <div className="flex-1 overflow-y-auto bg-slate-900/30 rounded p-2 custom-scrollbar">
                                        <div className="grid grid-cols-5 gap-2">
                                            {inventory.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE').map((item, idx) => (
                                                <button 
                                                    key={idx} 
                                                    onClick={() => recycleItem(item)}
                                                    onMouseEnter={() => setHoveredItem(item)}
                                                    onMouseLeave={() => setHoveredItem(null)}
                                                    className={`aspect-square bg-slate-800 border border-slate-600 hover:border-cyan-400 hover:bg-cyan-900/20 rounded flex flex-col items-center justify-center relative group`}
                                                    title="Click to Recycle"
                                                >
                                                    <ItemIcon item={item} size={16} />
                                                    <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/60 rounded">
                                                        <RefreshCcw size={16} className="text-cyan-400"/>
                                                    </div>
                                                </button>
                                            ))}
                                        </div>
                                        {inventory.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'REVIVE').length === 0 && (
                                            <div className="text-center text-slate-500 mt-10 italic">No recyclable items</div>
                                        )}
                                    </div>
                                </div>
                            )}

                            {blacksmithTab === 'CRAFT' && (
                                <div className="flex flex-col gap-3 h-full overflow-hidden">
                                    {/* Crafting UI code... */}
                                    <div className="flex flex-col gap-1 items-center bg-slate-900/50 p-3 rounded text-center mb-2">
                                        <div className="text-xs font-bold text-slate-400 uppercase mb-2">Combine Materials (10 → 1)</div>
                                        <div className="flex items-center justify-center gap-1 text-xs">
                                            {/* Common */}
                                            <div className="flex flex-col items-center relative group cursor-pointer" onClick={() => combineMaterials('COMMON')}>
                                                <div className="w-3 h-3 rounded-full bg-slate-200 mb-1"/>{materials.COMMON}
                                                <div className="absolute -bottom-6 text-[8px] opacity-0 group-hover:opacity-100 whitespace-nowrap bg-black px-1 rounded">10→1 Rare</div>
                                            </div>
                                            <ArrowRight size={10} className="text-slate-600" />
                                            {/* Rare */}
                                            <div className="flex flex-col items-center relative group cursor-pointer" onClick={() => combineMaterials('RARE')}>
                                                <div className="w-3 h-3 rounded-full bg-blue-400 mb-1"/>{materials.RARE}
                                                <div className="absolute -bottom-6 text-[8px] opacity-0 group-hover:opacity-100 whitespace-nowrap bg-black px-1 rounded">10→1 Epic</div>
                                            </div>
                                            <ArrowRight size={10} className="text-slate-600" />
                                            {/* Epic */}
                                            <div className="flex flex-col items-center relative group cursor-pointer" onClick={() => combineMaterials('EPIC')}>
                                                <div className="w-3 h-3 rounded-full bg-purple-400 mb-1"/>{materials.EPIC}
                                                <div className="absolute -bottom-6 text-[8px] opacity-0 group-hover:opacity-100 whitespace-nowrap bg-black px-1 rounded">10→1 Leg.</div>
                                            </div>
                                            <ArrowRight size={10} className="text-slate-600" />
                                            {/* Legendary */}
                                            <div className="flex flex-col items-center relative group cursor-pointer" onClick={() => combineMaterials('LEGENDARY')}>
                                                <div className="w-3 h-3 rounded-full bg-yellow-400 mb-1"/>{materials.LEGENDARY}
                                                <div className="absolute -bottom-6 text-[8px] opacity-0 group-hover:opacity-100 whitespace-nowrap bg-black px-1 rounded">10→1 Myth</div>
                                            </div>
                                            <ArrowRight size={10} className="text-slate-600" />
                                            {/* Mythic */}
                                            <div className="flex flex-col items-center">
                                                <div className="w-3 h-3 rounded-full bg-red-500 mb-1"/>{materials.MYTHIC}
                                            </div>
                                        </div>
                                    </div>
                                    <div className="flex-1 overflow-y-auto custom-scrollbar p-1 flex flex-col gap-3">
                                    {(['COMMON', 'RARE', 'EPIC', 'LEGENDARY', 'MYTHIC'] as Rarity[]).map(rarity => {
                                        const cost = 3;
                                        const have = materials[rarity];
                                        const canCraft = have >= cost;
                                        let color = 'text-slate-200';
                                        let bg = 'bg-slate-700';
                                        if (rarity === 'RARE') { color = 'text-blue-400'; bg = 'bg-blue-900/30'; }
                                        if (rarity === 'EPIC') { color = 'text-purple-400'; bg = 'bg-purple-900/30'; }
                                        if (rarity === 'LEGENDARY') { color = 'text-yellow-400'; bg = 'bg-yellow-900/30'; }
                                        if (rarity === 'MYTHIC') { color = 'text-red-500'; bg = 'bg-red-900/30'; }

                                        return (
                                            <div key={rarity} className={`p-3 rounded border border-slate-700 ${bg} flex items-center justify-between`}>
                                                <div>
                                                    <div className={`font-bold ${color}`}>Random {rarity} Item</div>
                                                    <div className="text-xs text-slate-400">Cost: {cost} {rarity} Materials</div>
                                                </div>
                                                <div className="flex flex-col items-end gap-1">
                                                    <div className="text-xs text-slate-500">Have: {have}</div>
                                                    <button 
                                                        onClick={() => craftItem(rarity)}
                                                        disabled={!canCraft}
                                                        className={`px-3 py-1 rounded text-xs font-bold ${canCraft ? 'bg-slate-100 text-black hover:scale-105' : 'bg-slate-800 text-slate-500 cursor-not-allowed'}`}
                                                    >
                                                        CRAFT
                                                    </button>
                                                </div>
                                            </div>
                                        )
                                    })}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    {activeShopTab === 'SKILLS' && (
                        <div className="flex flex-col gap-6">
                            <div className="text-center text-sm text-slate-400">
                                Upgrade existing skills or unlock new ones using Skill Points.
                            </div>

                            {/* ACTIVE SKILLS SECTION */}
                            <div className="flex flex-col gap-3">
                                <div className="text-xs font-bold text-yellow-400 uppercase tracking-widest border-b border-yellow-400/30 pb-1 mb-2">Active Skills</div>
                                {Object.entries(SKILLS_INFO).map(([key, info]) => {
                                    // @ts-ignore
                                    if (info.type !== 'ACTIVE') return null;
                                    // @ts-ignore
                                    if (info.classType && info.classType !== hero) return null;

                                    const skillKey = key as keyof SkillLevels;
                                    const currentLevel = skillLevels[skillKey];
                                    const cost = key === 'special' ? 5 : (currentLevel === 0 ? 3 : currentLevel + 1); // 5 SP for special
                                    const canAfford = skillPoints >= cost;
                                    const isMaxed = key === 'special' && currentLevel > 0; // Special is 1 level only for now

                                    if (isMaxed) return null; 

                                    return (
                                        <div key={key} className={`group relative p-3 bg-slate-800 border ${currentLevel > 0 ? 'border-yellow-600' : 'border-slate-700 opacity-90'} rounded flex items-center gap-4 hover:bg-slate-750 transition-colors`}>
                                            <div className="w-12 h-12 bg-slate-900 rounded flex items-center justify-center shrink-0 border border-slate-700 text-yellow-400">
                                                {renderSkillIcon(key)}
                                            </div>
                                            <div className="flex-1">
                                                <div className="flex items-center gap-2">
                                                    <span className="font-bold text-slate-200">{info.name}</span>
                                                    {currentLevel > 0 && <span className={`text-[10px] px-1.5 py-0.5 rounded font-mono font-bold ${currentLevel > 0 ? 'bg-yellow-900 text-yellow-500' : 'bg-slate-700 text-slate-500'}`}>
                                                        Lv.{currentLevel}
                                                    </span>}
                                                </div>
                                                <div className="text-xs text-slate-400 truncate w-48">{info.description}</div>
                                            </div>
                                            <button 
                                                onClick={() => upgradeSkill(skillKey)}
                                                disabled={!canAfford}
                                                className={`flex flex-col items-center px-4 py-2 rounded font-bold min-w-[5rem] ${canAfford ? 'bg-yellow-600 hover:bg-yellow-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}
                                            >
                                                <span className="text-[10px] uppercase">{currentLevel === 0 ? 'UNLOCK' : 'UPGRADE'}</span>
                                                <span className="flex items-center gap-1 text-xs">
                                                    <Star size={10} fill="currentColor" /> {cost}
                                                </span>
                                            </button>
                                        </div>
                                    );
                                })}
                            </div>

                            {/* PASSIVE SKILLS SECTION */}
                            <div className="flex flex-col gap-3">
                                <div className="text-xs font-bold text-blue-400 uppercase tracking-widest border-b border-blue-400/30 pb-1 mb-2">Passive Skills</div>

                                {equipment.pet && equipment.pet.petSkill && (
                                    <div className="group relative p-3 bg-slate-800 border border-slate-600 rounded flex items-center gap-4 hover:bg-slate-750 transition-colors">
                                        <div className="w-12 h-12 bg-slate-900 rounded flex items-center justify-center shrink-0 border border-slate-700 text-pink-400">
                                            <Ghost size={24} />
                                        </div>
                                        <div className="flex-1">
                                            <div className="flex items-center gap-2">
                                                <span className="font-bold text-slate-200">Pet Skill: {equipment.pet.petSkill.replace('_', ' ')}</span>
                                                <span className="text-[10px] px-1.5 py-0.5 rounded font-mono font-bold bg-pink-900 text-pink-400">ACTIVE</span>
                                            </div>
                                            <div className="text-xs text-slate-400 truncate w-48">{equipment.pet.description}</div>
                                        </div>
                                    </div>
                                )}

                                {Object.entries(SKILLS_INFO).map(([key, info]) => {
                                    // @ts-ignore
                                    if (info.type !== 'PASSIVE') return null;
                                    // @ts-ignore
                                    if (info.classType && info.classType !== hero) return null;

                                    const skillKey = key as keyof SkillLevels;
                                    const currentLevel = skillLevels[skillKey];
                                    const cost = currentLevel === 0 ? 3 : currentLevel + 1;
                                    const canAfford = skillPoints >= cost;

                                    return (
                                        <div key={key} className={`group relative p-3 bg-slate-800 border ${currentLevel > 0 ? 'border-slate-600' : 'border-slate-700 opacity-90'} rounded flex items-center gap-4 hover:bg-slate-750 transition-colors`}>
                                            <div className="w-12 h-12 bg-slate-900 rounded flex items-center justify-center shrink-0 border border-slate-700">
                                                {renderSkillIcon(key)}
                                            </div>
                                            <div className="flex-1">
                                                <div className="flex items-center gap-2">
                                                    <span className="font-bold text-slate-200">{info.name}</span>
                                                    <span className={`text-[10px] px-1.5 py-0.5 rounded font-mono font-bold ${currentLevel > 0 ? 'bg-blue-900 text-blue-300' : 'bg-slate-700 text-slate-500'}`}>
                                                        Lv.{currentLevel}
                                                    </span>
                                                </div>
                                                <div className="text-xs text-slate-400 truncate w-48">{info.description}</div>
                                            </div>
                                            <button 
                                                onClick={() => upgradeSkill(skillKey)}
                                                disabled={!canAfford}
                                                className={`flex flex-col items-center px-4 py-2 rounded font-bold min-w-[5rem] ${canAfford ? 'bg-yellow-600 hover:bg-yellow-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}
                                            >
                                                <span className="text-[10px] uppercase">{currentLevel === 0 ? 'UNLOCK' : 'UPGRADE'}</span>
                                                <span className="flex items-center gap-1 text-xs">
                                                    <Star size={10} fill="currentColor" /> {cost}
                                                </span>
                                            </button>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    )}
                </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

import { create } from 'zustand';
import { GameStatus, PlayerStats, Upgrade, Item, DropData, SkillLevels, Rarity, HeroClass, PassiveSkillState, Obstacle, CrateData, ItemType, GameNotification, BossData, AbilityType, GameStatistics, UpgradeType, ActionResult } from './types';
import { ITEMS_POOL, HERO_STATS, PETS_POOL, ARENA_SIZE, COLORS, INVENTORY_LIMIT, UPGRADES_POOL, POTION_STACK_LIMIT } from './constants';
import { Vector3 } from 'three';

interface GameState {
  status: GameStatus;
  hero: HeroClass;
  score: number; // Used as GOLD
  accumulatedWaveGold: number; // Gold accumulated from wave clears
  gems: number; 
  level: number;
  experience: number;
  experienceToNextLevel: number;
  skillPoints: number; // New: Skill Points
  health: number;
  mana: number;
  playerPosition: Vector3;
  stats: PlayerStats;
  baseStats: PlayerStats;

  // Wave System
  wave: number;
  waveTimer: number; // Seconds elapsed in current wave
  recentRuns: number[]; // Store wave reached in previous runs

  // Statistics
  gameStats: GameStatistics;

  skillLevels: SkillLevels;
  passiveSkillState: PassiveSkillState; // For UI cooldowns

  activeAbilityQ: AbilityType | null; 
  activeAbilityR: AbilityType | null;

  inventory: Item[];
  maxInventorySlots: number;
  materials: Record<Rarity, number>;

  equipment: {
    weapon: Item | null;
    armor: Item | null;
    accessory: Item | null;
    pet: Item | null;
  };

  gachaResults: Item[];
  upgradeOptions: Upgrade[]; // For Roguelike selection

  drops: DropData[];
  obstacles: Obstacle[];
  crates: CrateData[];
  minimapEnemies: { x: number, z: number, type: number }[]; // For UI Minimap

  skills: {
    dash: number;
    q: number;
    r: number;
    e: number; // New E Skill
  };
  skillMaxCooldowns: {
    dash: number;
    q: number;
    r: number;
    e: number;
  };

  // E Skill States
  earthwall: { active: boolean, position: Vector3, timer: number, radius: number };
  warVitalityTimer: number;
  sprintTimer: number;

  rageMode: boolean;
  rageTimer: number;

  potionCooldown: number;
  barrierCooldown: number;
  isInvincible: boolean;
  invincibilityTimer: number;
  levelUpVisualTimer: number; // Visual flash for level up
  reviveAnimTimer: number; // New: Visual flash for revive

  // Pet Logic
  petReviveCooldown: number;

  bossData: BossData;

  // UI State
  isInventoryOpen: boolean;
  isShopOpen: boolean;
  isCharacterSheetOpen: boolean;
  isCodexOpen: boolean; // New Codex State
  activeShopTab: 'SUPPLIES' | 'PETS' | 'SUMMON' | 'SKILLS' | 'BLACKSMITH';
  notifications: GameNotification[];
  actionResult: ActionResult | null;

  // Internal throttling
  lastInventoryFullNotification: number;

  setStatus: (status: GameStatus) => void;
  toggleInventory: () => void;
  toggleCharacterSheet: () => void;
  toggleCodex: () => void;
  openSpecificShop: (tab: 'SUPPLIES' | 'PETS' | 'SUMMON' | 'SKILLS' | 'BLACKSMITH') => void;
  closeAllUI: () => void;
  clearActionResult: () => void;

  selectHero: (hero: HeroClass) => void;
  startGame: () => void;
  addScore: (amount: number) => void;
  addGems: (amount: number) => void;
  addExperience: (amount: number) => void;
  takeDamage: (amount: number) => void;
  breakCrate: (id: number) => void;
  damageCrate: (id: number, amount: number) => void; // Kept for compatibility
  useMana: (amount: number) => boolean;
  heal: (amount: number) => void;
  restoreMana: (amount: number) => void;
  setPlayerPosition: (pos: Vector3) => void;
  triggerInvincibility: (duration: number) => void;
  setInvincible: (invincible: boolean) => void; // Legacy compatibility
  applyUpgrade: (upgrade: Upgrade) => void;
  selectUpgrade: (upgrade: Upgrade) => void;
  upgradeSkill: (skill: keyof SkillLevels) => void;
  equipItem: (item: Item) => void;
  unequipItem: (slot: 'weapon' | 'armor' | 'accessory' | 'pet') => void;
  autoEquip: () => void;
  buyItem: (item: Item, quantity?: number) => boolean;
  sellItem: (item: Item) => void;
  sellItems: (items: Item[]) => void;
  massSell: (rarity: Rarity) => void; // New Mass Sell
  recycleItem: (item: Item) => void;
  massRecycle: (rarity: Rarity) => void;
  combineMaterials: (fromRarity: Rarity) => void;
  craftItem: (rarity: Rarity) => boolean;
  buyInventorySlots: () => boolean;
  performSummon: (amount: 1 | 10) => boolean;
  clearGachaResults: () => void;
  upgradeItem: (item: Item) => { success: boolean, msg: string, newItem?: Item };
  resetGame: () => void;

  spawnDrop: (position: Vector3, type: 'ITEM' | 'XP' | 'GOLD' | 'GEM', value: number, rarityOverride?: Rarity) => void;
  collectDrop: (id: number) => void;
  triggerSkillCooldown: (skill: 'dash' | 'q' | 'r' | 'e') => void;
  activateRage: () => void;
  updatePassiveCooldowns: (state: Partial<PassiveSkillState>) => void;
  tickCooldowns: (delta: number) => void;
  updateMinimapEnemies: (enemies: { x: number, z: number, type: number }[]) => void;

  // E Skill Actions
  activateEarthwall: (pos: Vector3) => void;
  activateWarVitality: () => void;
  activateSprint: () => void;

  advanceWave: () => void;
  setBossData: (data: Partial<BossData>) => void;

  addNotification: (message: string, color?: string, type?: 'ITEM' | 'BOSS' | 'SYSTEM', action?: { label: string, onClick: () => void }) => void;
  removeNotification: (id: string) => void;
  handleInventoryFull: () => void;
}

const INITIAL_STATS: PlayerStats = {
  maxHealth: 100,
  maxMana: 100,
  regen: 0.5,
  manaRegen: 0.5,
  moveSpeed: 10,
  damage: 15,
  fireRate: 2.0,
  projectileSpeed: 20,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 4.0, 
  cooldownReduction: 0,
  magnetRadius: 5.0,
  critRate: 0.05,
  critDamage: 1.5,
