          case 'freezing': return <Gem className="text-blue-300" />;
          case 'freezeSpell': return <Zap className="text-blue-400" />;
          case 'gravity': return <CircleDollarSign className="text-purple-500" />;
          case 'stamp': return <Hammer className="text-orange-500" />;
          case 'rage': return <Flame className="text-red-600" />;
          case 'storm': return <Tornado className="text-indigo-400" />;
          case 'special': return <Star className="text-emerald-400" />;
