                            if (d < minDist) {
                                minDist = d;
                                target = e;
                            }
                        }
                    }
                    if (target) {
                        const dmg = pet.petValue || 20;
                        target.health -= dmg;
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: target.position, damage: dmg, isCrit: true, damageType: 'FIRE' } 
                        }));
                    }
                }
             }
        }
        // LOOTING LOGIC
        else if (pet.petSkill === 'COLLECT') {
            lootCooldown.current -= delta;

            // 1. Find Target if None and Cooldown Ready
            if (targetDropId.current === null && lootCooldown.current <= 0) {
                // Find nearest ITEM drop
                let nearestDrop = null;
                let minDist = 30; // Max range to spot item

                for(const drop of drops) {
                    if (drop.active && drop.type === 'ITEM') {
                        const d = drop.position.distanceTo(currentPos.current);
                        if (d < minDist) {
                            minDist = d;
                            nearestDrop = drop;
                        }
                    }
                }

                if (nearestDrop) {
                    targetDropId.current = nearestDrop.id;
                }
            }

            // 2. Chase Target
            if (targetDropId.current !== null) {
                const drop = drops.find(d => d.id === targetDropId.current);
                if (drop && drop.active && drop.type === 'ITEM') {
                    // Override default follow behavior
                    targetPos.copy(drop.position);
                    targetPos.y = 1.0; 

                    // Check pickup
                    if (currentPos.current.distanceTo(drop.position) < 1.0) {
                        collectDrop(drop.id);
                        targetDropId.current = null;
                        lootCooldown.current = 5.0; // 5 Seconds Cooldown
                    }
                } else {
                    // Drop gone or invalid
                    targetDropId.current = null;
                }
            }
        }
    }

    // Smooth Lerp Movement
    const speed = targetDropId.current !== null ? 15 : 3; // Fast when chasing loot
    currentPos.current.lerp(targetPos, delta * speed);

    meshRef.current.position.copy(currentPos.current);
    meshRef.current.lookAt(playerPosition.x, 1, playerPosition.z);
    meshRef.current.rotation.z = Math.sin(state.clock.elapsedTime * 5) * 0.1;
  });

  if (!pet) return null;

  let color = '#a3e635'; // Blob Green
  if (pet.id.includes('bat')) color = '#a855f7';
  if (pet.id.includes('wolf')) color = '#60a5fa';
  if (pet.id.includes('fairy')) color = '#f472b6';
  if (pet.id.includes('dragon')) color = '#fbbf24';

  return (
      <group>
        <mesh ref={meshRef} castShadow>
             {pet.id.includes('dragon') ? (
                 <dodecahedronGeometry args={[0.5, 0]} />
             ) : pet.id.includes('fairy') ? (
                 <octahedronGeometry args={[0.3, 0]} />
             ) : (
                 <sphereGeometry args={[0.4, 8, 8]} />
             )}
             <meshStandardMaterial color={color} emissive={color} emissiveIntensity={0.5} roughness={0.2} />
        </mesh>
      </group>
  );
};

import { create } from 'zustand';
import { Vector3 } from 'three';
import { 
    GameStatus, HeroClass, Item, PlayerStats, Upgrade, 
    Obstacle, DropData, CrateData, SkillLevels, PassiveSkillState, 
    ItemType, Rarity 
} from './types';
import { HERO_STATS, ARENA_SIZE, ITEMS_POOL, PETS_POOL } from './constants';

interface GameState {
    status: GameStatus;
    stats: PlayerStats;
    heroClass: HeroClass;
    level: number;
    experience: number;
    maxExperience: number;
    gold: number;
    inventory: Item[];
    equipment: {
        weapon: Item | null;
        armor: Item | null;
        accessory: Item | null;
        pet: Item | null;
    };
    drops: DropData[];
    obstacles: Obstacle[];
    crates: CrateData[];
    skillLevels: SkillLevels;
    passiveSkillState: PassiveSkillState;
    earthwall: { active: boolean, position: Vector3, radius: number };
    activeShop: string | null;

    // Actions
    setStatus: (status: GameStatus) => void;
    addXp: (amount: number) => void;
    addGold: (amount: number) => void;
    spawnDrop: (position: Vector3, type: 'ITEM' | 'GOLD' | 'XP' | 'GEM', value: number, item?: Item | null) => void;
    collectDrop: (id: number) => void;
    damageCrate: (id: number, amount: number) => void;
    equipItem: (item: Item) => void;
    unequipItem: (slot: 'weapon' | 'armor' | 'accessory' | 'pet') => void;
    autoEquip: () => void;
    openSpecificShop: (shopType: string) => void;
    heal: (amount: number) => void;
    updatePassiveCooldowns: (updates: Partial<PassiveSkillState>) => void;
    generateWorld: () => void;
    setHero: (hero: HeroClass) => void;
}

const INITIAL_STATS: PlayerStats = {
    maxHealth: 100,
    maxMana: 100,
    regen: 0,
    manaRegen: 1,
    moveSpeed: 10,
    damage: 10,
    fireRate: 1,
    projectileSpeed: 20,
    multishot: 0,
    spread: 0.1,
    dashCooldown: 3,
    cooldownReduction: 0,
    magnetRadius: 5,
    critRate: 0.05,
    critDamage: 1.5,
    defense: 0,
    skillDamage: 1,
    knockback: 1,
    dodge: 0,
    returnDamage: 0,
    doubleCastChance: 0,
    lifeSteal: 0
};

export const useGameStore = create<GameState>((set, get) => ({
    status: GameStatus.MENU,
    stats: { ...INITIAL_STATS },
    heroClass: 'ARCHER',
    level: 1,
    experience: 0,
    maxExperience: 100,
    gold: 0,
    inventory: [],
    equipment: {
        weapon: null,
        armor: null,
        accessory: null,
        pet: null
    },
    drops: [],
    obstacles: [],
    crates: [],
    earthwall: { active: false, position: new Vector3(), radius: 0 },
    activeShop: null,

    skillLevels: { 
        orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 1, weapon: 1, barrier: 1, storm: 0, special: 0,
        piercing: 0, burning: 0, freezing: 0, freezeSpell: 0, gravity: 0, stamp: 0, rage: 0
    },
    passiveSkillState: { 
        orbitalCooldown: 0, orbitalMaxCooldown: 1, 
        thunderCooldown: 0, thunderMaxCooldown: 6,
        burningCooldown: 0, burningMaxCooldown: 8, 
        freezingCooldown: 0, freezingMaxCooldown: 7,
        blizzardCooldown: 0, blizzardMaxCooldown: 10,
        stampCooldown: 0, stampMaxCooldown: 10,
        stormCooldown: 0, stormMaxCooldown: 15
    },

    setStatus: (status) => set({ status }),

    setHero: (hero) => {
        const heroData = HERO_STATS[hero];
        const initialWeapon = ITEMS_POOL.find(i => i.id === heroData.weaponId);
        set({ 
            heroClass: hero, 
            stats: { ...INITIAL_STATS, ...heroData.stats },
            equipment: { weapon: initialWeapon || null, armor: null, accessory: null, pet: null }
        });
    },

    generateWorld: () => {
        const obstacles: Obstacle[] = [];
        const crates: CrateData[] = [];
        const count = 40; 

        // Generate Obstacles
        for (let i = 0; i < count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const r = Math.random() * (ARENA_SIZE / 2 - 10);
            const x = Math.cos(angle) * r;
            const z = Math.sin(angle) * r;

            // Avoid center
            if (Math.sqrt(x*x + z*z) < 15) continue;

            const typeRoll = Math.random();
            let type: any = 'TREE';
            let radius = 1;

            if (typeRoll > 0.9) { type = 'HOUSE'; radius = 4; }
            else if (typeRoll > 0.7) { type = 'ROCK'; radius = 1.5; }
            else if (typeRoll > 0.5) { type = 'FENCE'; radius = 1; }

            obstacles.push({
                id: i,
                position: new Vector3(x, 0, z),
                type,
                radius,
                scale: 0.8 + Math.random() * 0.4
            });
        }

        // Generate Crates
        for (let i = 0; i < 20; i++) {
             const angle = Math.random() * Math.PI * 2;
             const r = 20 + Math.random() * (ARENA_SIZE / 2 - 30);
             crates.push({
                 id: i,
                 position: new Vector3(Math.cos(angle) * r, 0.5, Math.sin(angle) * r),
                 active: true,
                 rotation: Math.random() * Math.PI,
                 hp: 20,
                 maxHp: 20
             });
        }

        set({ obstacles, crates });
    },

    addXp: (amount) => set(state => {
        let newXp = state.experience + amount;
        let newLevel = state.level;
        let newMaxXp = state.maxExperience;
        let status = state.status;

        if (newXp >= newMaxXp) {
            newXp -= newMaxXp;
            newLevel++;
            newMaxXp = Math.floor(newMaxXp * 1.2);
            status = GameStatus.LEVEL_UP;
        }

        return { experience: newXp, level: newLevel, maxExperience: newMaxXp, status };
    }),

    addGold: (amount) => set(state => ({ gold: state.gold + amount })),

    heal: (amount) => set(state => ({ 
        stats: { ...state.stats, maxHealth: state.stats.maxHealth } // Just triggering update, health logic usually in Player or component state if transient. 
        // Note: Ideally health is transient in Player component for performance, but for potion/pet effect we might need to signal Player.
        // For this implementation, we assume Player component subscribes to store or handles health locally. 
        // We will dispatch an event for health restoration.
    })),

    spawnDrop: (position, type, value, item) => set(state => {
        const newDrop: DropData = {
            id: Math.random(),
            position: position.clone(),
            type,
            value,
            item: item || null,
            active: true,
            rotation: Math.random() * Math.PI
        };
        return { drops: [...state.drops, newDrop] };
    }),

    collectDrop: (id) => set(state => {
        const drop = state.drops.find(d => d.id === id);
        if (!drop) return {};

        let updates: Partial<GameState> = { drops: state.drops.filter(d => d.id !== id) };

        if (drop.type === 'XP') {
            get().addXp(drop.value);
        } else if (drop.type === 'GOLD') {
            get().addGold(drop.value);
        } else if (drop.type === 'ITEM' && drop.item) {
            updates.inventory = [...state.inventory, drop.item];
        } else if (drop.type === 'GEM') {
            get().addGold(drop.value * 10);
        }

        return updates;
    }),

    damageCrate: (id, amount) => set(state => {
        const newCrates = state.crates.map(c => {
            if (c.id === id) {
                return { ...c, hp: c.hp - amount, active: c.hp - amount > 0 };
            }
            return c;
        });
        return { crates: newCrates };
    }),

    equipItem: (item) => set(state => {
        const slotMap: Record<string, 'weapon' | 'armor' | 'accessory' | 'pet'> = {
            'WEAPON': 'weapon', 'ARMOR': 'armor', 'ACCESSORY': 'accessory', 'PET': 'pet'
        };
        const slot = slotMap[item.type];
        if (!slot) return {}; // Potions/etc

        const currentEquipped = state.equipment[slot];
        const newInventory = state.inventory.filter(i => i.id !== item.id);
        if (currentEquipped) newInventory.push(currentEquipped);

        // Recalculate Stats
        // Simplified: Reset to base + equip stats
        // Real implementation would be more complex

        return {
            inventory: newInventory,
            equipment: { ...state.equipment, [slot]: item }
        };
    }),

    unequipItem: (slot) => set(state => {
        const item = state.equipment[slot];
        if (!item) return {};

        if (state.inventory.length >= 50) return {}; // Full

        return {
            equipment: { ...state.equipment, [slot]: null },
            inventory: [...state.inventory, item]
        };
    }),

    autoEquip: () => {
        // Simple implementation
    },

    openSpecificShop: (shopType) => set({ activeShop: shopType, status: GameStatus.SHOP }),

    updatePassiveCooldowns: (updates) => set(state => ({
        passiveSkillState: { ...state.passiveSkillState, ...updates }
    })),
}));

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus, BulletData } from '../types';

interface BulletManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
}

const dummy = new Object3D();

export const BulletManager: React.FC<BulletManagerProps> = ({ bulletsDataRef }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { status } = useGameStore();

  // Local storage initialization for the ref if empty
  useEffect(() => {
    if (bulletsDataRef.current.length === 0) {
        bulletsDataRef.current = new Array(MAX_BULLETS).fill(0).map((_, i) => ({
            id: i,
            active: false,
            position: new Vector3(),
            velocity: new Vector3(),
            lifetime: 0,
            type: 'MAGIC',
            hitIds: []
        }));
    }
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
    }
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const bullets = bulletsDataRef.current;
    let activeCount = 0;

    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets[i];
        if (b.active) {
            b.position.add(b.velocity.clone().multiplyScalar(delta));
            b.lifetime -= delta;

            if (b.lifetime <= 0) {
                b.active = false;
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);
                dummy.lookAt(b.position.clone().add(b.velocity));

                // Scale based on type
                let s = 1;
                if (b.type === 'FIREBALL') s = 1.5;
                if (b.type === 'AXE') {
                    s = 2;
                    dummy.rotation.z += state.clock.elapsedTime * 15; // Spin axe
                }
                dummy.scale.set(s, s, s);
            }
            activeCount++;
        } else {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      <sphereGeometry args={[0.2, 8, 8]} />
      <meshStandardMaterial color={COLORS.bulletPlayer} emissive={COLORS.bulletPlayer} emissiveIntensity={2} />
    </instancedMesh>
  );
};

