import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, Plane, Raycaster } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, CAMERA_HEIGHT } from '../constants';
import { GameStatus, BulletData, EnemyData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface PlayerProps {
    bulletsDataRef: React.MutableRefObject<BulletData[]>;
    enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
    targetPosRef: React.MutableRefObject<Vector3>;
    enemiesDataRef: React.MutableRefObject<EnemyData[]>;
    spatialGrid: React.MutableRefObject<SpatialHashGrid>;
}

export const Player: React.FC<PlayerProps> = ({ 
    bulletsDataRef, 
    enemyBulletsDataRef,
    targetPosRef,
    enemiesDataRef,
    spatialGrid
}) => {
    const { status, stats, equipment, skillLevels, setStatus, heal } = useGameStore();
    const meshRef = useRef<THREE.Mesh>(null);
    const axeSpinRef = useRef<THREE.Group>(null);
    const { camera, mouse, raycaster } = useThree();

    // Local State
    const playerPos = useRef(new Vector3(0, 0, 0));
    const isMoving = useRef(false);
    const lastShot = useRef(0);
    const health = useRef(stats.maxHealth); // Transient health for performance

    // Inputs
    const keys = useRef<{ [key: string]: boolean }>({});

    // Event Listeners
    React.useEffect(() => {
        const onKeyDown = (e: KeyboardEvent) => keys.current[e.code] = true;
        const onKeyUp = (e: KeyboardEvent) => keys.current[e.code] = false;
        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);

        // Init health from store on mount/remount
        health.current = stats.maxHealth;

        // Listen for heal events
        const unsub = useGameStore.subscribe((state, prevState) => {
            if (state.stats.maxHealth !== prevState.stats.maxHealth) {
                 // Update HP cap if needed
            }
        });

        return () => {
            window.removeEventListener('keydown', onKeyDown);
            window.removeEventListener('keyup', onKeyUp);
            unsub();
        };
    }, [stats.maxHealth]);

    useFrame((state, delta) => {
        if (status !== GameStatus.PLAYING) return;
        if (!meshRef.current) return;

        // 1. Movement
        const speed = stats.moveSpeed * delta;
        const moveDir = new Vector3();
        if (keys.current['KeyW'] || keys.current['ArrowUp']) moveDir.z -= 1;
        if (keys.current['KeyS'] || keys.current['ArrowDown']) moveDir.z += 1;
        if (keys.current['KeyA'] || keys.current['ArrowLeft']) moveDir.x -= 1;
        if (keys.current['KeyD'] || keys.current['ArrowRight']) moveDir.x += 1;

        if (moveDir.length() > 0) {
            moveDir.normalize().multiplyScalar(speed);
            playerPos.current.add(moveDir);
            isMoving.current = true;
        } else {
            isMoving.current = false;
        }

        // Update Ref Mesh
        meshRef.current.position.copy(playerPos.current);
        // Sync global store position (throttled ideally, but for now simple)
        useGameStore.setState({ playerPosition: playerPos.current.clone() });

        // 2. Camera Follow
        const camTarget = playerPos.current.clone().add(new Vector3(0, CAMERA_HEIGHT, 24));
        camera.position.lerp(camTarget, 0.1);
        camera.lookAt(playerPos.current);

        // 3. Aiming
        raycaster.setFromCamera(mouse, camera);
        const plane = new Plane(new Vector3(0, 1, 0), 0);
        const target = new Vector3();
        raycaster.ray.intersectPlane(plane, target);
        if (target) {
            targetPosRef.current.copy(target);
            meshRef.current.lookAt(target.x, 1, target.z);
        }

        // 4. Shooting
        lastShot.current += delta;
        const fireRate = 1 / stats.fireRate;

        if (keys.current['Space'] || (mouse.x !== 0 && mouse.y !== 0)) { // Auto-fire or mouse based
             if (lastShot.current >= fireRate) {
                 lastShot.current = 0;
                 shoot(target);
             }
        }

        // 5. Collision with Enemy Bullets
        // Simple iteration or spatial grid? Enemy bullets are few enough to iterate
        const enemyBullets = enemyBulletsDataRef.current;
        for (const eb of enemyBullets) {
            if (eb.active && eb.position.distanceTo(playerPos.current) < PLAYER_RADIUS + 0.3) {
                takeDamage(10); // Base enemy dmg
                eb.active = false;
            }
        }

        // 6. Collision with Enemies
        const nearbyEnemies = spatialGrid.current.query(playerPos.current.x, playerPos.current.z);
        for(const eid of nearbyEnemies) {
            const enemy = enemiesDataRef.current[eid];
            if (enemy && enemy.active && enemy.position.distanceTo(playerPos.current) < PLAYER_RADIUS + enemy.radius) {
                takeDamage(5 * delta); // Contact damage
            }
        }

        // 7. Visuals (Axe Spin)
        if (axeSpinRef.current) {
            if (equipment.weapon?.ability === 'AXE_SPIN') {
                axeSpinRef.current.visible = true;
                axeSpinRef.current.position.copy(playerPos.current);
                axeSpinRef.current.rotation.y += delta * 5;
            } else {
                axeSpinRef.current.visible = false;
            }
        }
    });

    const shoot = (target: Vector3) => {
        const bullets = bulletsDataRef.current;
        const count = 1 + Math.floor(stats.multishot);
        const spread = stats.spread;

        for (let i = 0; i < count; i++) {
            const bullet = bullets.find(b => !b.active);
            if (bullet) {
                bullet.active = true;
                bullet.lifetime = 2.0;
                bullet.position.copy(playerPos.current).add(new Vector3(0, 1, 0));

                const dir = target.clone().sub(playerPos.current).normalize();

                // Spread
                if (count > 1) {
                    const angle = (i - (count - 1) / 2) * spread;
                    dir.applyAxisAngle(new Vector3(0, 1, 0), angle);
                }

                bullet.velocity.copy(dir).multiplyScalar(stats.projectileSpeed);
                bullet.type = equipment.weapon?.projectileType || 'MAGIC';
                bullet.hitIds = [];
            }
        }
    };

    const takeDamage = (amount: number) => {
        // Defense mitigation
        const dmg = Math.max(1, amount - stats.defense * 0.5);
        health.current -= dmg;

        // Dispatch event for UI
        window.dispatchEvent(new CustomEvent('damage', { 
            detail: { position: playerPos.current, damage: dmg, isCrit: false, isPlayer: true } 
        }));

        if (health.current <= 0) {
            setStatus(GameStatus.GAME_OVER);
        }
    };

    return (
        <group>
            <mesh ref={meshRef} castShadow receiveShadow>
                <boxGeometry args={[1, 2, 1]} />
                <meshStandardMaterial color={COLORS.player} />
            </mesh>

            {/* Axe Spin Visuals */}
            <group ref={axeSpinRef} visible={false}>
                {[0, 1, 2, 3].map((i) => (
                    <group key={i} rotation={[0, (i / 4) * Math.PI * 2, 0]}>
                        <mesh position={[2, 0, 0]}> 
                            <boxGeometry args={[0.5, 0.1, 0.5]} /> 
                            <meshStandardMaterial color="#ef4444" emissive="#7f1d1d" emissiveIntensity={0.5} />
                        </mesh>
                    </group>
                ))}
            </group>
        </group>
    );
};

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage } from 'three';
import { useGameStore } from '../store';
import { COLORS, ARENA_SIZE } from '../constants';
import { GameStatus, BulletData, EnemyData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemiesDataRef: React.MutableRefObject<EnemyData[]>;
  spatialGrid: React.MutableRefObject<SpatialHashGrid>;
}

const dummy = new Object3D();
const MAX_ENEMIES = 400;

export const EnemyManager: React.FC<EnemyManagerProps> = ({ 
    bulletsDataRef, 
    enemyBulletsDataRef,
    enemiesDataRef,
    spatialGrid 
}) => {
    const meshRef = useRef<InstancedMesh>(null);
    const { status, playerPosition, stats, spawnDrop } = useGameStore();
    const spawnTimer = useRef(0);
    const waveCap = 50; // Simple wave cap

    useLayoutEffect(() => {
        if (meshRef.current) {
            meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
            // Link data for access in other components if needed
            meshRef.current.userData.enemies = enemiesDataRef.current;
            meshRef.current.name = "EnemyMesh";
        }
    }, []);

    useFrame((state, delta) => {
        if (status !== GameStatus.PLAYING || !meshRef.current) return;

        // 1. Spawning
        spawnTimer.current += delta;
        const enemies = enemiesDataRef.current;
        let activeCount = enemies.filter(e => e.active).length;

        if (spawnTimer.current > 0.5 && activeCount < waveCap) {
            spawnTimer.current = 0;
            const enemy = enemies.find(e => !e.active);
            if (enemy) {
                // Spawn logic
                const angle = Math.random() * Math.PI * 2;
                const r = 20 + Math.random() * 10; // Spawn distance
                enemy.active = true;
                enemy.position.set(playerPosition.x + Math.cos(angle) * r, 0, playerPosition.z + Math.sin(angle) * r);
                enemy.health = 20 + stats.damage * 2; // Scale HP
                enemy.maxHealth = enemy.health;
                enemy.type = 0;
                enemy.speed = 4 + Math.random();
            }
        }

        // 2. Updates & Rendering
        spatialGrid.current.clear();

        for (let i = 0; i < MAX_ENEMIES; i++) {
            const e = enemies[i];
            if (e.active) {
                // Movement
                const dir = playerPosition.clone().sub(e.position).normalize();
                e.position.add(dir.multiplyScalar(e.speed * delta));

                // Boundary check
                if (Math.abs(e.position.x) > ARENA_SIZE || Math.abs(e.position.z) > ARENA_SIZE) {
                    // Push back
                    e.position.lerp(new Vector3(0,0,0), 0.01);
                }

                // Add to grid
                spatialGrid.current.add(e.id, e.position.x, e.position.z);

                // Collision with Player Bullets
                const bullets = bulletsDataRef.current;
                for (const b of bullets) {
                    if (b.active && !b.hitIds.includes(e.id)) {
                        if (b.position.distanceTo(e.position) < e.radius + 0.2) {
                             // Hit!
                             const isCrit = Math.random() < stats.critRate;
                             const dmg = stats.damage * (isCrit ? stats.critDamage : 1);
                             e.health -= dmg;

                             // Dispatch Damage Text
                             window.dispatchEvent(new CustomEvent('damage', { 
                                detail: { position: e.position, damage: dmg, isCrit, damageType: b.type } 
                             }));

                             // Knockback
                             e.position.add(b.velocity.clone().normalize().multiplyScalar(stats.knockback));

                             if (b.pierce && b.pierce > 0) {
                                 b.pierce--;
                                 b.hitIds.push(e.id);
                             } else {
                                 b.active = false;
                             }
                        }
                    }
                }

                // Death
                if (e.health <= 0) {
                    e.active = false;
                    spawnDrop(e.position, 'XP', 10);
                    dummy.position.set(0, -100, 0);
                } else {
                    dummy.position.copy(e.position);
                    dummy.scale.set(e.scale, e.scale, e.scale);
                }
            } else {
                dummy.position.set(0, -100, 0);
                dummy.scale.set(0, 0, 0);
            }
            dummy.updateMatrix();
            meshRef.current.setMatrixAt(i, dummy.matrix);
        }
        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
            <boxGeometry args={[1, 1, 1]} />
            <meshStandardMaterial color={COLORS.enemySlime} />
        </instancedMesh>
    );
};

import React, { useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, DynamicDrawUsage } from 'three';
import { useGameStore } from '../store';
import { GameStatus } from '../types';
import { COLORS } from '../constants';

const dummy = new Object3D();
const MAX_DROPS = 200;

export const DropManager: React.FC = () => {
    const meshRef = useRef<InstancedMesh>(null);
    const { status, drops, playerPosition, stats, collectDrop } = useGameStore();

    useLayoutEffect(() => {
        if (meshRef.current) {
            meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
        }
    }, []);

    useFrame((state, delta) => {
        if (status !== GameStatus.PLAYING || !meshRef.current) return;

        let instanceIndex = 0;

        drops.forEach((drop, i) => {
             if (!drop.active) return;

             // Magnet Logic
             const dist = drop.position.distanceTo(playerPosition);
             if (dist < stats.magnetRadius) {
                 const dir = playerPosition.clone().sub(drop.position).normalize();
                 drop.position.add(dir.multiplyScalar(15 * delta)); // Fly to player

                 if (dist < 1.0) {
                     collectDrop(drop.id);
                     return; // Collected
                 }
             }

             // Visuals
             drop.rotation += delta;
             dummy.position.copy(drop.position);
             dummy.position.y = 0.5 + Math.sin(state.clock.elapsedTime * 2 + i) * 0.2;
             dummy.rotation.set(0, drop.rotation, 0);

             if (drop.type === 'XP') dummy.scale.set(0.3, 0.3, 0.3);
             else if (drop.type === 'GOLD') dummy.scale.set(0.4, 0.1, 0.4);
             else dummy.scale.set(0.5, 0.5, 0.5);

             // Set Color workaround: In a real app we might use InstancedBufferAttribute for colors
             // For now, assuming all drops share material or we use a texture atlas. 
             // Since we can't easily change color per instance without custom shader or attribute, 
             // we'll just render them all as 'Items' (white) or mixed.
             // A common R3F trick is setting color via attribute.

             dummy.updateMatrix();
             if (instanceIndex < MAX_DROPS) {
                 meshRef.current!.setMatrixAt(instanceIndex, dummy.matrix);
                 // We would set color attribute here if we had one set up
                 instanceIndex++;
             }
        });

        // Hide unused instances
        for(let j=instanceIndex; j<MAX_DROPS; j++) {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0,0,0);
            dummy.updateMatrix();
            meshRef.current.setMatrixAt(j, dummy.matrix);
        }

        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_DROPS]} frustumCulled={false}>
             <dodecahedronGeometry args={[0.5, 0]} />
             <meshStandardMaterial color={COLORS.dropXp} emissive={COLORS.dropXp} emissiveIntensity={0.5} />
        </instancedMesh>
    );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3 } from 'three';
import { useGameStore } from '../store';
import { GameStatus, EnemyData, BulletData } from '../types';
import { SpatialHashGrid } from '../utils/SpatialHashGrid';

interface SkillManagerProps {
    enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
    bulletsDataRef: React.MutableRefObject<BulletData[]>;
    targetPosRef: React.MutableRefObject<Vector3>;
    enemiesDataRef: React.MutableRefObject<EnemyData[]>;
}

export const SkillManager: React.FC<SkillManagerProps> = ({ 
    enemyBulletsDataRef, bulletsDataRef, targetPosRef, enemiesDataRef 
}) => {
    const { status, skillLevels, stats, playerPosition, updatePassiveCooldowns } = useGameStore();

    // Cooldown Timers
    const thunderTimer = useRef(0);
    const thunderVisualTimer = useRef(0);
    const orbitalTimer = useRef(0);

    // Visuals State (refs to not re-render component)
    const thunderPositions = useRef<Vector3[]>([]);

    useFrame((state, delta) => {
        if (status !== GameStatus.PLAYING) return;

        // 1. Thunder Skill
        if (skillLevels.thunder > 0) {
            thunderTimer.current += delta;
            const maxCd = 6.0;
            updatePassiveCooldowns({ thunderCooldown: maxCd - thunderTimer.current, thunderMaxCooldown: maxCd });

            if (thunderTimer.current > maxCd) {
                const enemies = enemiesDataRef.current;
                const activeEnemies = enemies.filter(e => e.active && e.position.distanceTo(playerPosition) < 25);

                if (activeEnemies.length > 0) {
                    thunderTimer.current = 0;
                    const hitCount = skillLevels.thunder;
                    const hits: Vector3[] = [];

                    for(let i=0; i<hitCount; i++) {
                        if (activeEnemies.length === 0) break;
                        const idx = Math.floor(Math.random() * activeEnemies.length);
                        const target = activeEnemies[idx];

                        const isCrit = Math.random() < stats.critRate;
                        const dmg = stats.damage * 1.5 * (isCrit ? stats.critDamage : 1);

                        target.health -= dmg;
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: target.position, damage: dmg, isCrit, damageType: 'MAGIC' } 
                        }));

                        hits.push(target.position.clone());
                        activeEnemies.splice(idx, 1);
                    }

                    thunderPositions.current = hits;
                    thunderVisualTimer.current = 0.25;
                }
            }
        }

        // Thunder Visuals Cleanup
        if (thunderVisualTimer.current > 0) {
            thunderVisualTimer.current -= delta;
            if (thunderVisualTimer.current <= 0) {
                thunderPositions.current = [];
            }
        }
    });

    return (
        <group>
            {/* Thunder Visuals */}
            {thunderPositions.current.map((pos, i) => (
                <mesh key={`thunder-${i}`} position={pos}>
                    <cylinderGeometry args={[0.1, 0.1, 10, 8]} />
                    <meshBasicMaterial color="#fbbf24" />
                </mesh>
            ))}
        </group>
    );
};

