export const GameUI: React.FC = () => {
  const { 
    status, health, mana, stats, score, gems, level, experience, experienceToNextLevel, skillPoints,
    inventory, maxInventorySlots, materials, equipment, setStatus, skills, skillMaxCooldowns, skillLevels, passiveSkillState, gachaResults,
    startGame, resetGame, applyUpgrade, selectUpgrade, upgradeOptions, equipItem, unequipItem, buyItem, upgradeItem, sellItem, sellItems, autoEquip, performSummon, clearGachaResults, selectHero, hero, potionCooldown,
    wave, waveTimer, recentRuns, bossData, gameStats,
    isInventoryOpen, isShopOpen, toggleInventory, toggleShop, activeShopTab, closeAllUI, openSpecificShop,
    notifications, removeNotification, upgradeSkill, toggleCharacterSheet, isCharacterSheetOpen, baseStats, activeAbilityQ, activeAbilityR,
    recycleItem, massRecycle, combineMaterials, craftItem, buyInventorySlots, actionResult, clearActionResult, massSell,
    isCodexOpen, toggleCodex
  } = useGameStore();

  const [hoveredItem, setHoveredItem] = useState<Item | null>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  // Blacksmith State
  const [blacksmithTab, setBlacksmithTab] = useState<'UPGRADE' | 'RECYCLE' | 'CRAFT'>('UPGRADE');
  const [selectedUpgradeItem, setSelectedUpgradeItem] = useState<Item | null>(null);

  // Codex State
  const [codexTab, setCodexTab] = useState<'ITEMS' | 'PETS' | 'SKILLS'>('ITEMS');
  const [codexSearch, setCodexSearch] = useState('');

  // Summon Animation State
  const [isSummoning, setIsSummoning] = useState(false);

  // Sell Confirmation State
  const [sellConfirmationItem, setSellConfirmationItem] = useState<Item | null>(null);

  // Track Mouse for Tooltip
  useEffect(() => {
      const handleMouseMove = (e: MouseEvent) => {
          setMousePos({ x: e.clientX, y: e.clientY });
      };
      window.addEventListener('mousemove', handleMouseMove);
      return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Auto Dismiss Action Result
  useEffect(() => {
      if (actionResult) {
          // If successful upgrade, update the selection
          if (actionResult.success && actionResult.type === 'UPGRADE' && actionResult.item) {
              setSelectedUpgradeItem(actionResult.item);
          }

          const timer = setTimeout(() => {
              clearActionResult();
          }, 2000);
          return () => clearTimeout(timer);
      }
  }, [actionResult, clearActionResult]);

  // Sorted Inventory: Rarity (High -> Low) then CP (High -> Low)
  const sortedInventory = useMemo(() => {
      return [...inventory].sort((a, b) => {
          const rarityOrder: Record<string, number> = { MYTHIC: 5, LEGENDARY: 4, EPIC: 3, RARE: 2, COMMON: 1 };
          const rA = rarityOrder[a.rarity] || 0;
          const rB = rarityOrder[b.rarity] || 0;
          if (rA !== rB) return rB - rA; // Descending Rarity
          return calculateItemCP(b) - calculateItemCP(a); // Descending CP
      });
  }, [inventory]);

  const onInventoryItemClick = (item: Item, isConsumable: boolean, canEquip: boolean) => {
      if (!isConsumable && canEquip) {
          equipItem(item);
      }
  };

  const handleSummon = async (amount: 1 | 10) => {
      setIsSummoning(true);
      // Wait for animation
      await new Promise(resolve => setTimeout(resolve, 2000));
      const success = performSummon(amount);
      if (!success) {
          setIsSummoning(false);
      } else {
          setIsSummoning(false);
      }
  };

  const handleSellClick = (item: Item) => {
      if (item.rarity === 'EPIC' || item.rarity === 'LEGENDARY' || item.rarity === 'MYTHIC') {
          setSellConfirmationItem(item);
      } else {
          sellItem(item);
      }
