import { UPGRADES_POOL, ITEMS_POOL, HERO_STATS, PETS_POOL, SKILLS_INFO, ARENA_SIZE, SHOP_POSITIONS } from '../constants';
import { 
  Heart, Zap, Sparkles, RotateCcw, 
  Backpack, Shield, Sword, Gem, X, User, Flame, Wind, ShoppingBag, Coins, Hammer, MoveRight, Activity, Magnet, Ghost, Dices, Timer, Trash2, CheckCircle2, ShieldCheck, Wand, FlaskConical, CircleDollarSign, Package,
  Crosshair, Axe, Wand2, Hexagon, Layers, BookOpen, Star, ArrowUpCircle, Trophy, RefreshCcw, Anvil, ArrowRight, Sun, Tornado, Skull, Check, AlertTriangle, Book, Search, Lock, Play, Pause
} from 'lucide-react';
