const ActiveSkillSlot: React.FC<{
    icon: React.ReactNode;
    level: number;
    cooldown: number;
    label: string;
    desc: string;
    borderColor: string;
    active: boolean;
    manaCost?: number;
    currentMana?: number;
    heroClass?: string;
