    const onCooldown = cooldown > 0;

    return (
        <div className="relative group flex flex-col items-center">
            <div className={`w-14 h-14 md:w-16 md:h-16 bg-slate-900 border-2 rounded-xl flex items-center justify-center relative overflow-hidden transition-all 
