                {!canAfford && !onCooldown && active && (
                    <div className="absolute inset-0 bg-blue-900/60 flex items-center justify-center z-10 flex-col">
                        <span className="text-blue-200 text-xs font-bold drop-shadow-md">NO</span>
                        <span className="text-blue-200 text-xs font-bold drop-shadow-md">MANA</span>
                    </div>
                )}
                {active && (
                    <div className="absolute bottom-1 right-1 flex gap-0.5 z-20">
                        {level > 5 ? (
                            <span className="text-[10px] font-bold bg-black/60 px-1 rounded text-yellow-400">Lv{level}</span>
                        ) : (
                            [...Array(Math.max(0, level))].map((_, i) => (
                                <div key={i} className="w-1 h-1 bg-yellow-400 rounded-full shadow-sm" />
                            ))
                        )}
                    </div>
                )}
            </div>
            <div className="absolute -top-3 left-1/2 -translate-x-1/2 text-[10px] font-bold bg-slate-800 px-1.5 rounded border border-slate-600 whitespace-nowrap z-30">
